INSERT INTO `ms_gravitysmtp_events` VALUES (1,'2026-04-13 14:27:16','2026-04-13 14:27:16','sent','postmark','Test Email from Gravity SMTP','<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n	<meta charset=\"UTF-8\">\n	<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n	<title>Email Template</title>\n	<style>\n		body {\n			margin: 0;\n			padding: 0;\n			background: #fff;\n			font-family: inter, -apple-system, blinkmacsystemfont, \'Segoe UI\', roboto, oxygen-sans, ubuntu, cantarell, \'Helvetica Neue\', sans-serif;\n		}\n\n		img {\n			border: 0 none;\n			height: auto;\n			line-height: 100%;\n			outline: none;\n			text-decoration: none;\n		}\n\n		a img {\n			border: 0 none;\n		}\n\n		table, td {\n			border-collapse: collapse;\n		}\n\n		#bodyTable {\n			height: 100% !important;\n			margin: 0;\n			padding: 0;\n			width: 100% !important;\n		}\n		.wrapper {\n			max-width: 680px;\n			margin: 0 auto;\n		}\n		.content {\n			padding: 20px 20px 200px;\n		}\n\n		@media only screen and (max-width: 480px) {\n			.content {\n				padding: 20px 20px 120px;\n			}\n		}\n	</style>\n</head>\n<body>\n<table id=\"bodyTable\" role=\"presentation\" width=\"100%\" align=\"center\"\n       style=\"background: url(\'https://moresenz-staging.novionline.nl/wp-content/plugins/gravitysmtp/assets/images/email-templates/gravitysmtp-arrow-bg.png\') no-repeat top right / 514px 647px #fff; margin: 0;\">\n	<tr>\n		<td>\n			<table class=\"wrapper\" role=\"presentation\">\n				<!-- Header with Logo -->\n				<tr>\n					<td style=\"padding: 70px 20px 32px; text-align: center;\">\n						<img src=\"https://moresenz-staging.novionline.nl/wp-content/plugins/gravitysmtp/assets/images/email-templates/gravitysmtp-email-logo.png\" alt=\"Logo\"\n						     style=\"display: block; margin: 0 auto; max-width: 200px\">\n					</td>\n				</tr>\n				<!-- Content Area -->\n				<tr>\n					<td class=\"content\">\n						<img src=\"https://moresenz-staging.novionline.nl/wp-content/plugins/gravitysmtp/assets/images/email-templates/send-test/gravitysmtp-success.png\" alt=\"Mail Icon\"\n						     style=\"display: block; margin: 0 auto; max-width: 308px\">\n						<h1 style=\"color: #242748; text-align: center; font-family: inter, -apple-system, blinkmacsystemfont, \'Segoe UI\', roboto, oxygen-sans, ubuntu, cantarell, \'Helvetica Neue\', sans-serif; font-size: 30px; font-style: normal; font-weight: 600; line-height: 30px; padding: 20px 0 32px; margin: 0;\">Test Successful</h1>\n						<div\n							style=\"border-radius: 3px; border: 1px solid #d5d7e9; box-shadow: 0px 2px 2px 0px rgba(58, 58, 87, 0.06);\">\n							<p style=\"margin: 0; padding: 12px 24px; background: #f6f9fc; font-family: inter, -apple-system, blinkmacsystemfont, \'Segoe UI\', roboto, oxygen-sans, ubuntu, cantarell, \'Helvetica Neue\', sans-serif; border-bottom: 1px solid #d5d7e9; color: #242748; font-size: 14px; font-style: normal; font-weight: 500; line-height: 18px;\">Congratulations! Gravity SMTP is sending emails correctly!</p>\n							<p style=\"color: #5b5e80; background: #fff; margin: 0; padding: 16px 24px; font-family: inter, -apple-system, blinkmacsystemfont, \'Segoe UI\', roboto, oxygen-sans, ubuntu, cantarell, \'Helvetica Neue\', sans-serif; font-size: 14px; font-style: normal; font-weight: 400; line-height: 20px\">Gravity SMTP is taking care of sending your emails, so now you can focus on the content of your emails and leave the technical details to us.</p>\n						</div>\n					</td>\n				</tr>\n			</table>\n		</td>\n	</tr>\n</table>\n</body>\n</html>','a:6:{s:2:\"to\";O:53:\"Gravity_Forms\\Gravity_SMTP\\Utils\\Recipient_Collection\":1:{s:10:\"recipients\";a:1:{i:0;O:42:\"Gravity_Forms\\Gravity_SMTP\\Utils\\Recipient\":2:{s:5:\"email\";s:19:\"peter@novionline.nl\";s:4:\"name\";s:0:\"\";}}}s:4:\"from\";s:40:\"MoreSenz Cinema <moresenz@novionline.nl>\";s:7:\"headers\";a:2:{s:12:\"content-type\";s:23:\"Content-type: text/html\";s:4:\"from\";s:28:\"From: moresenz@novionline.nl\";}s:11:\"attachments\";a:0:{}s:6:\"source\";s:12:\"Gravity SMTP\";s:6:\"params\";a:1:{s:7:\"headers\";a:3:{s:12:\"Content-Type\";s:16:\"application/json\";s:6:\"Accept\";s:16:\"application/json\";s:23:\"X-Postmark-Server-Token\";s:36:\"714f2ba6-4a25-47b7-becb-30cd5a7bbab0\";}}}');
