:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:69:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"Meet the New SeedProd Dashboard: Built the Way You Work\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"https://www.seedprod.com/announcement-new-seedprod-dashboard/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 20 Oct 2025 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:8:\"seedprod\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:25:\"WordPress website builder\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=40834\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:358:\"<p>The new SeedProd dashboard is here. Enjoy a cleaner design, simpler navigation, and faster access to everything you need to build your website.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-new-seedprod-dashboard/\">Meet the New SeedProd Dashboard: Built the Way You Work</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"John Turner\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:14014:\"<div><img fetchpriority=\"high\" decoding=\"async\" width=\"800\" height=\"420\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/meet-the-new-dashboard-built-the-way-you-work-2x-800x420.jpg\" class=\"attachment-large size-large wp-post-image\" alt=\"Meet the New SeedProd Dashboard: Built the Way You Work\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/meet-the-new-dashboard-built-the-way-you-work-2x-800x420.jpg 800w, https://www.seedprod.com/wp-content/uploads/2025/10/meet-the-new-dashboard-built-the-way-you-work-2x-400x210.jpg 400w, https://www.seedprod.com/wp-content/uploads/2025/10/meet-the-new-dashboard-built-the-way-you-work-2x-768x403.jpg 768w, https://www.seedprod.com/wp-content/uploads/2025/10/meet-the-new-dashboard-built-the-way-you-work-2x-50x26.jpg 50w, https://www.seedprod.com/wp-content/uploads/2025/10/meet-the-new-dashboard-built-the-way-you-work-2x.jpg 1200w\" sizes=\"(max-width: 800px) 100vw, 800px\" /></div>|||\n<p>Every great website starts with momentum, that feeling of knowing exactly what to do next. The new SeedProd dashboard is designed to give you that from the very first click.</p>\n\n\n\n<p>We’ve reimagined the layout to make your workflow faster and more intuitive. The tools you use most are front and center, so you can move from idea to finished page with less effort and more focus.</p>\n\n\n\n<p>It’s a clean experience that makes it easier to start building the website you need right away.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A Smarter Dashboard Designed by You</h2>\n\n\n\n<p>The new <a href=\"https://www.seedprod.com\" title=\"SeedProd - Best Drag &amp; Drop WordPress Website Builder\">SeedProd</a> dashboard began with a simple goal: to make building your website easier.</p>\n\n\n\n<p>We looked closely at how people use SeedProd each day, like where they click, what they open most, and how they move through different tools.</p>\n\n\n\n<p>That research helped us understand what matters most:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>A clear starting point</li>\n\n\n\n<li>Fewer steps</li>\n\n\n\n<li>Faster access to what you need</li>\n</ul>\n\n\n\n<p>Instead of adding more, <strong>we simplified</strong>.</p>\n\n\n\n<p>The new design removes clutter, highlights key actions, and keeps everything within easy reach.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img decoding=\"async\" width=\"800\" height=\"566\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-dashboard-redesign.png\" alt=\"New SeedProd dashboard showing simplified layout with main panels for setup, landing pages, and website builder.\" class=\"wp-image-40841\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-dashboard-redesign.png 800w, https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-dashboard-redesign-400x283.png 400w, https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-dashboard-redesign-768x543.png 768w, https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-dashboard-redesign-50x35.png 50w\" sizes=\"(max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>The result is a dashboard shaped by real use and real feedback, built to help you move quickly and stay focused on creating.</p>\n\n\n\n<h2 class=\"wp-block-heading\">One Dashboard for Every Way You Build</h2>\n\n\n\n<p>The new SeedProd dashboard brings everything together in a clean workspace, so everything you need to create and manage your website starts in one place.</p>\n\n\n\n<p>At the center of the update are four main panels that give you quick access to every part of your workflow.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Your New Starting Point</h3>\n\n\n\n<p>The <strong>Setup &amp; Status</strong> panel is now where your projects begin.</p>\n\n\n\n<p>From here, you can enable Coming Soon or Maintenance Mode, set up custom Login and 404 pages, or <a href=\"https://www.seedprod.com/how-to-create-a-landing-page/\" title=\"How to Create a Landing Page in WordPress (Without Code)\">create new landing pages</a> from one simple panel.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img decoding=\"async\" width=\"737\" height=\"480\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/setup-status-panel-seedprod.png\" alt=\"Setup and Status panel in SeedProd showing options to enable Coming Soon Mode, Maintenance Mode, Login, and 404 pages.\" class=\"wp-image-40842\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/setup-status-panel-seedprod.png 737w, https://www.seedprod.com/wp-content/uploads/2025/10/setup-status-panel-seedprod-400x261.png 400w, https://www.seedprod.com/wp-content/uploads/2025/10/setup-status-panel-seedprod-50x33.png 50w\" sizes=\"(max-width: 737px) 100vw, 737px\" /></figure>\n\n\n\n<p>The Landing Pages dashboard also includes the Import and Export feature, now moved here for easier access. You can quickly reuse your favorite designs or transfer them between sites with a few easy clicks.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"624\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-landing-pages-dashboard-seedprod.png\" alt=\"Updated Landing Pages dashboard in SeedProd with Import and Export options for reusing and transferring page designs.\" class=\"wp-image-40843\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-landing-pages-dashboard-seedprod.png 800w, https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-landing-pages-dashboard-seedprod-400x312.png 400w, https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-landing-pages-dashboard-seedprod-768x599.png 768w, https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-landing-pages-dashboard-seedprod-50x39.png 50w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>The Setup &amp; Status panel also connects directly to the Website Builder dashboard, where you’ll find the theme import and export options and a cleaner toggle to enable your SeedProd theme.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"570\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-website-builder-dashboard-seedprod.png\" alt=\"SeedProd Website Builder dashboard with theme import and export controls and toggle to enable the active SeedProd theme.\" class=\"wp-image-40844\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-website-builder-dashboard-seedprod.png 800w, https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-website-builder-dashboard-seedprod-400x285.png 400w, https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-website-builder-dashboard-seedprod-768x547.png 768w, https://www.seedprod.com/wp-content/uploads/2025/10/redesigned-website-builder-dashboard-seedprod-50x36.png 50w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>At the bottom of that first panel, you’ll see a subscriber count that shows how many people have signed up through your SeedProd opt-in forms. It’s an easy way to track your growth right from your dashboard.</p>\n\n\n\n<h3 class=\"wp-block-heading\">More Panels to Keep You Connected</h3>\n\n\n\n<p>The remaining panels are designed to give you everything you need  at a glance, from <a href=\"https://www.seedprod.com/best-wordpress-plugins/\" title=\"11 Must-Have WordPress Plugins for Business Websites\">trusted WordPress plugin</a> suggestions to quick access to support and product news.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Recommended Plugins:</strong> Find WordPress tools that work seamlessly with SeedProd, all tested for compatibility and performance.</li>\n\n\n\n<li><strong>Help &amp; Resources:</strong> Jump straight to documentation, video tutorials, or the support center without leaving your dashboard.</li>\n\n\n\n<li><strong>What’s New:</strong> Catch up on the latest product updates, announcements, and new feature releases as they happen.</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"330\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/help-whats-new-panels-seedprod.png\" alt=\"SeedProd dashboard panels for Recommended Plugins, Help and Resources, and What’s New updates.\" class=\"wp-image-40845\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/help-whats-new-panels-seedprod.png 800w, https://www.seedprod.com/wp-content/uploads/2025/10/help-whats-new-panels-seedprod-400x165.png 400w, https://www.seedprod.com/wp-content/uploads/2025/10/help-whats-new-panels-seedprod-768x317.png 768w, https://www.seedprod.com/wp-content/uploads/2025/10/help-whats-new-panels-seedprod-50x21.png 50w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">A Simpler Sidebar to Match</h3>\n\n\n\n<p>The SeedProd sidebar menu has been redesigned to match the clean, focused layout of the new dashboard. It’s shorter, clearer, and built around the tools you use most.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"536\" height=\"447\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/admin-menu-seedprod.png\" alt=\"Redesigned SeedProd sidebar menu showing Dashboard, AI Theme Builder, Website Builder, Landing Pages, and Settings.\" class=\"wp-image-40846\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/admin-menu-seedprod.png 536w, https://www.seedprod.com/wp-content/uploads/2025/10/admin-menu-seedprod-400x334.png 400w, https://www.seedprod.com/wp-content/uploads/2025/10/admin-menu-seedprod-50x42.png 50w\" sizes=\"auto, (max-width: 536px) 100vw, 536px\" /></figure>\n</div>\n\n\n<p>You’ll now see fewer main sections:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Dashboard</strong></li>\n\n\n\n<li><strong>AI Theme Builder</strong> &#8211; Build your full website instantly at <a href=\"https://ai.seedprod.com/\" target=\"_blank\" rel=\"noopener\" title=\"\">ai.seedprod.com</a>.</li>\n\n\n\n<li><strong>Website Builder</strong> &#8211; Access and edit your SeedProd theme templates and parts.</li>\n\n\n\n<li><strong>Landing Pages</strong> &#8211; Manage your pages, templates, and page modes.</li>\n\n\n\n<li><strong>Settings</strong> &#8211; Organized into tabs for General, Subscribers, Recommended Plugins, and About Us.</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"612\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-settings-redesign.png\" alt=\"New Settings screen in SeedProd with organized tabs for General, Subscribers, Recommended Plugins, and About Us.\" class=\"wp-image-40847\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-settings-redesign.png 800w, https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-settings-redesign-400x306.png 400w, https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-settings-redesign-768x588.png 768w, https://www.seedprod.com/wp-content/uploads/2025/10/seedprod-settings-redesign-50x38.png 50w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>This new structure makes it easier to move between sections without losing focus. Whatever you&#8217;re building, everything you need is right where you expect it.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What This Redesign Means for You</h2>\n\n\n\n<p>This redesign is made for every kind of website creator. Whether you’re <a href=\"https://www.seedprod.com/how-to-create-a-wordpress-website-for-beginners/\" title=\"How to Create a WordPress Website for Beginners\">building your first site</a> or managing projects for clients, it helps you move quickly and stay focused.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Small business owners</strong> can launch professional websites without the learning curve. Tools like landing pages, coming soon mode, and maintenance mode are all easy to find and ready to use.</li>\n</ul>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Freelancers and agencies</strong> can deliver projects faster with a layout their whole team can pick up right away. Everything is organized for smoother handoffs and quicker results.</li>\n</ul>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Marketers</strong> can create high-converting campaigns with direct access to templates and subscriber insights in one clear workspace.</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"538\" src=\"https://www.seedprod.com/wp-content/uploads/2025/10/CleanShot2025-10-07at134120-ezgifcom-optimize.gif\" alt=\"Animated preview showing the new SeedProd dashboard workflow and transitions between panels.\" class=\"wp-image-40848\"/></figure>\n\n\n\n<p>We designed this around a simple idea: <strong>the best interface is the one that gets out of your way</strong>. No hidden menus, no complex navigation, just the tools you need, right when you need them.</p>\n\n\n\n<h3 class=\"wp-block-heading\">See the New Dashboard for Yourself</h3>\n\n\n\n<p>The redesigned SeedProd dashboard is ready for you to try, built to help you work faster and keep building without distractions. Log in to your account and see how easy it feels to move from idea to launch.</p>\n\n\n\n<p>This simpler design also makes room for what’s next. We’re already working on new AI tools that will build on this and make creating with <a href=\"https://www.seedprod.com/what-is-seedprod-ai/\" title=\"\">SeedProd AI</a> even easier.</p>\n\n\n\n<p>Thank you for being part of the SeedProd community and helping shape where we go next.</p>\n\n\n\n<p><strong>John Turner<em> </em>and the SeedProd team.</strong></p>\n\n\n\n<p><em>P.S. Don’t have SeedProd Pro yet? Click here to&nbsp;<a href=\"https://www.seedprod.com/pricing/\">get SeedProd Pro</a>&nbsp;and join over 1 million website owners who trust SeedProd to create professional WordPress websites without the hassle.</em></p>The post <a href=\"https://www.seedprod.com/announcement-new-seedprod-dashboard/\">Meet the New SeedProd Dashboard: Built the Way You Work</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:69:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"New SeedProd AI: From Idea to WordPress Site in 60 Seconds\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://www.seedprod.com/announcement-seedprod-ai-redesign/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 29 Sep 2025 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:10:\"AI content\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:20:\"ai WordPress builder\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:11:\"seedprod ai\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=40797\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:356:\"<p>Meet the new SeedProd AI: Instantly generate a WordPress website in under a minute, preview the design, and bring it live with SeedProd Pro.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-seedprod-ai-redesign/\">New SeedProd AI: From Idea to WordPress Site in 60 Seconds</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"John Turner\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11725:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"420\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/new-seedProd-ai-dot-800x420.jpg\" class=\"attachment-large size-large wp-post-image\" alt=\"New SeedProd AI: From Idea to WordPress Site in 60 Seconds\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/new-seedProd-ai-dot-800x420.jpg 800w, https://www.seedprod.com/wp-content/uploads/2025/09/new-seedProd-ai-dot-400x210.jpg 400w, https://www.seedprod.com/wp-content/uploads/2025/09/new-seedProd-ai-dot-768x403.jpg 768w, https://www.seedprod.com/wp-content/uploads/2025/09/new-seedProd-ai-dot-50x26.jpg 50w, https://www.seedprod.com/wp-content/uploads/2025/09/new-seedProd-ai-dot.jpg 1200w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></div>|||\n<p>Launching a new website often takes weeks of planning, design, and setup. But what if you could skip all of that and go from idea to a complete WordPress website in less time than it takes to make coffee?</p>\n\n\n\n<p>With <a href=\"https://ai.seedprod.com/\" title=\"\">SeedProd AI</a>, that is exactly what you can do. In under 60 seconds, you will have a full website with a homepage, about, services, and contact pages ready to explore.</p>\n\n\n\n<p>SeedProd AI has been available in beta for a little while, but now we have completely redesigned it. The new version is smoother, faster, and easier than ever to use.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What’s New in the Redesigned SeedProd AI</h2>\n\n\n\n<p>With this redesign, SeedProd AI is more powerful and beginner-friendly than before:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Simpler Workflow</strong>: Enter your company name and describe your business. SeedProd AI handles the rest.</li>\n\n\n\n<li><strong>Instant Playground Preview</strong>: Open your generated site in WordPress Playground and click through all the pages to see the design in action.</li>\n\n\n\n<li><strong>Complete Website Packages</strong>: Get a full website with homepage, about, services, and contact pages.</li>\n\n\n\n<li><strong>One-Click Import</strong>: When you are ready, download your site as a .zip file and import it into WordPress using SeedProd’s Import Theme option.</li>\n</ul>\n\n\n\n<p>For more details, you can see our guide on <a href=\"https://www.seedprod.com/what-is-seedprod-ai/\" title=\"\">what SeedProd AI is and how it works</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">How to Build a Complete Website with SeedProd AI</h2>\n\n\n\n<p>To get started with SeedProd AI, visit <a href=\"https://ai.seedprod.com/\" title=\"\">ai.seedprod.com</a> and enter your preferred email address.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"783\" height=\"662\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-home.webp\" alt=\"SeedProd AI homepage with option to enter email address to get started\" class=\"wp-image-40798\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-home.webp 783w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-home-400x338.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-home-768x649.webp 768w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-home-50x42.webp 50w\" sizes=\"auto, (max-width: 783px) 100vw, 783px\" /></figure>\n\n\n\n<p>You&#8217;ll then get a magic link sent to your email so you can login securely.</p>\n\n\n\n<p>Once you&#8217;ve logged in, click the Create New Website button.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"539\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-create-new-website.webp\" alt=\"SeedProd AI dashboard with “Create New Website” button highlighted\" class=\"wp-image-40799\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-create-new-website.webp 800w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-create-new-website-400x270.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-create-new-website-768x517.webp 768w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-create-new-website-50x34.webp 50w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>On the next page, enter your company name and some information about your business. This is what SeedProd AI will use to generate the various pages, elements, images, and content for your website. So be as detailed as you like in this step.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"674\" height=\"587\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/webite-description-seedprod-ai.webp\" alt=\"Form in SeedProd AI to enter company name and business description\" class=\"wp-image-40800\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/webite-description-seedprod-ai.webp 674w, https://www.seedprod.com/wp-content/uploads/2025/09/webite-description-seedprod-ai-400x348.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/webite-description-seedprod-ai-50x44.webp 50w\" sizes=\"auto, (max-width: 674px) 100vw, 674px\" /></figure>\n\n\n\n<p>You can also let AI choose your website&#8217;s color palette for you. If you already have a color scheme in mind, simply uncheck the option and select your own colors.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"661\" height=\"423\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/choose-website-colors-seedprod-ai.webp\" alt=\"SeedProd AI option to let AI choose website color palette or select custom colors\" class=\"wp-image-40801\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/choose-website-colors-seedprod-ai.webp 661w, https://www.seedprod.com/wp-content/uploads/2025/09/choose-website-colors-seedprod-ai-400x256.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/choose-website-colors-seedprod-ai-50x32.webp 50w\" sizes=\"auto, (max-width: 661px) 100vw, 661px\" /></figure>\n\n\n\n<p>From there, simply click the <strong>Create My Website Now</strong> button.</p>\n\n\n\n<p>It will take under 60 seconds for SeedProd AI to take your vision and translate it into a complete WordPress website.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"679\" height=\"375\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/generating-website-seedprod-ai.webp\" alt=\"SeedProd AI progress screen showing website generation in under 60 seconds\" class=\"wp-image-40802\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/generating-website-seedprod-ai.webp 679w, https://www.seedprod.com/wp-content/uploads/2025/09/generating-website-seedprod-ai-400x221.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/generating-website-seedprod-ai-50x28.webp 50w\" sizes=\"auto, (max-width: 679px) 100vw, 679px\" /></figure>\n\n\n\n<p>Once it&#8217;s finished generating, click the View Your AI Creation button.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"683\" height=\"467\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/view-website-seedprod-ai.webp\" alt=\"SeedProd AI confirmation screen with button to view your AI-generated website\" class=\"wp-image-40803\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/view-website-seedprod-ai.webp 683w, https://www.seedprod.com/wp-content/uploads/2025/09/view-website-seedprod-ai-400x273.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/view-website-seedprod-ai-50x34.webp 50w\" sizes=\"auto, (max-width: 683px) 100vw, 683px\" /></figure>\n\n\n\n<p>This opens your design in WordPress Playground where you can preview the whole site, and click through the pages to get a feel for the design.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"486\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-generated-website-example.webp\" alt=\"Example of a complete WordPress website generated by SeedProd AI in WordPress Playground\" class=\"wp-image-40804\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-generated-website-example.webp 800w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-generated-website-example-400x243.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-generated-website-example-768x467.webp 768w, https://www.seedprod.com/wp-content/uploads/2025/09/seedprod-ai-generated-website-example-50x30.webp 50w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>If you&#8217;re happy with the generated design, head back to the SeedProd AI dashboard, and click the Download button.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"231\" src=\"https://www.seedprod.com/wp-content/uploads/2025/09/download-website-seedprod-ai-800x231.webp\" alt=\"SeedProd AI dashboard with option to download your generated website as a zip file\" class=\"wp-image-40805\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/09/download-website-seedprod-ai-800x231.webp 800w, https://www.seedprod.com/wp-content/uploads/2025/09/download-website-seedprod-ai-400x115.webp 400w, https://www.seedprod.com/wp-content/uploads/2025/09/download-website-seedprod-ai-768x221.webp 768w, https://www.seedprod.com/wp-content/uploads/2025/09/download-website-seedprod-ai-50x14.webp 50w, https://www.seedprod.com/wp-content/uploads/2025/09/download-website-seedprod-ai.webp 860w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>This saves your design as a .zip file, which allows you to use SeedProd&#8217;s &#8216;Import Theme&#8217; option to upload it to any WordPress website with SeedProd Pro installed.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Who Should Try SeedProd AI</h2>\n\n\n\n<p>SeedProd AI isn&#8217;t just for one type of user. The redesign makes it flexible enough to help in very different situations, whether you&#8217;re launching your first site, testing ideas for clients, or putting a side project online.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Small Business Owners</strong>: Get a professional website live in minutes so your business looks credible from day one.</li>\n\n\n\n<li><strong>Agencies</strong>: Prototype client websites instantly and cut project turnaround from weeks to hours.</li>\n\n\n\n<li><strong>Side Hustlers and Creators</strong>: Bring your new idea online right away with a real website you can own and grow.</li>\n</ul>\n\n\n\n<p>SeedProd AI adapts to your needs so you can move faster without sacrificing quality.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Try the New SeedProd AI Today</h2>\n\n\n\n<p>You can try the redesigned SeedProd AI right now at <a href=\"https://ai.seedprod.com/\" title=\"\">ai.seedprod.com</a>.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Generate up to 3 websites free</li>\n\n\n\n<li>Explore them instantly in WordPress Playground</li>\n\n\n\n<li>Publish with SeedProd Pro</li>\n</ul>\n\n\n\n<p>As always, thank you for your continued support of SeedProd. We look forward to bringing you more exciting updates designed to help you build better WordPress websites faster.</p>\n\n\n\n<p>John Turner and the SeedProd team.</p>\n\n\n\n<p><em>P.S. Don’t have SeedProd Pro yet? Click here to </em><a href=\"https://www.seedprod.com/pricing/\" title=\"\"><em>get S</em>e<em>edProd Pro</em></a><em> and join over 1 million website owners who trust SeedProd to create professional WordPress websites without the hassle.</em></p>The post <a href=\"https://www.seedprod.com/announcement-seedprod-ai-redesign/\">New SeedProd AI: From Idea to WordPress Site in 60 Seconds</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:69:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"New in SeedProd: Better Image Carousels + 15 Industry Themes\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://www.seedprod.com/announcement-better-image-carousels-industry-themes/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 24 Mar 2025 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:15:\"carousel slider\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:14:\"image carousel\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=39142\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:395:\"<p>Transform your website\'s image sliders with SeedProd\'s improved Image Carousel block - now with custom text, buttons, and controls to boost visitor engagement.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-better-image-carousels-industry-themes/\">New in SeedProd: Better Image Carousels + 15 Industry Themes</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"John Turner\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:13434:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"420\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/better-image-carousel-themes-800x420.png\" class=\"attachment-large size-large wp-post-image\" alt=\"New in SeedProd: Better Image Carousels + 15 Industry Themes\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/better-image-carousel-themes-800x420.png 800w, https://www.seedprod.com/wp-content/uploads/2025/03/better-image-carousel-themes-400x210.png 400w, https://www.seedprod.com/wp-content/uploads/2025/03/better-image-carousel-themes-768x403.png 768w, https://www.seedprod.com/wp-content/uploads/2025/03/better-image-carousel-themes-50x26.png 50w, https://www.seedprod.com/wp-content/uploads/2025/03/better-image-carousel-themes.png 1200w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></div>|||\n<p>It&#8217;s hard to keep visitors engaged on your website, even for experienced site owners like me. Especially when you only have 50 milliseconds to make an impression before they decide to stay or leave.</p>\n\n\n\n<p>Now think about how many customers you’re losing because your image sliders aren’t doing their job: <em>getting and keeping attention</em>.</p>\n\n\n\n<p>Every visitor who leaves without taking action is a missed lead or sale for your business.</p>\n\n\n\n<p>That&#8217;s why I&#8217;m thrilled to announce our completely revamped Image Carousel block for <a href=\"https://www.seedprod.com/\" title=\"SeedProd - Drag-and-Drop WordPress Website Builder\">SeedProd</a>.</p>\n\n\n\n<p>Now you can customize each slide with your own text and buttons, making your sliders more engaging and professional. It simplifies the entire process of creating attention-grabbing carousels and helps you turn more visitors into customers.</p>\n\n\n\n<p>Let’s take a closer look at what you can do with the new and improved Image Carousels.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"aioseo-add-text-and-buttons-to-image-carousels\">Add Text and Buttons to Image Carousels</h2>\n\n\n\n<p>Wouldn&#8217;t it be nice if you could add attention-grabbing headlines and call-to-action buttons right on your slider images? With this update to our <a class=\"heroickb_exit_link\" href=\"?hkb-redirect&#038;nonce=8ae63e5780&#038;check=402j9&#038;redirect=https%3A%2F%2Fwww.seedprod.com%2Fdocs%2Fimage-carousel%2F&#038;otype=unknown&#038;oid=0&#038;source=block-content\" title=\"Image Carousel Block\">Image Carousel block</a>, it’s super easy to do just that.</p>\n\n\n\n<p>You can now add custom headers, sub-headers, and clickable buttons to each slide individually.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"520\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-header-button.jpg\" alt=\"Adding a button and header text to image carousel in SeedProd\" class=\"wp-image-39143\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-header-button.jpg 662w, https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-header-button-400x314.jpg 400w, https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-header-button-50x39.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>But what sets SeedProd apart from other website builders, is how easy it is to fine-tune the details. While others overwhelm you with tons of settings, ours is designed to keep things simple and easy.</p>\n\n\n\n<p>It only takes a few clicks to set up your carousel and get it looking just the way you want.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"aioseo-make-your-text-pop\">Make Your Text Pop</h3>\n\n\n\n<p>For the entire carousel, you can add a color overlay to make the text and buttons stand out.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"438\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-overlay-color.jpg\" alt=\"Adding a color overlay and opacity to image carousel block in SeedProd\" class=\"wp-image-39144\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-overlay-color.jpg 662w, https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-overlay-color-400x265.jpg 400w, https://www.seedprod.com/wp-content/uploads/2025/03/image-carousel-overlay-color-50x33.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>You can also adjust the opacity, so images are still visible in the background.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"aioseo-easily-remove-distractions\">Easily Remove Distractions</h3>\n\n\n\n<p>By default, carousels will display navigation controls under the images. But if you want a cleaner look, you can now disable this option while still allowing the carousel to autoplay and cycle through each slide.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"404\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/hide-slider-navigation.png\" alt=\"Showing and hiding the Slider navigation controls in SeedProd\'s image carousel block\" class=\"wp-image-39145\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/hide-slider-navigation.png 662w, https://www.seedprod.com/wp-content/uploads/2025/03/hide-slider-navigation-400x244.png 400w, https://www.seedprod.com/wp-content/uploads/2025/03/hide-slider-navigation-50x31.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"aioseo-put-buttons-where-theyre-noticed\">Put Buttons Where They’re Noticed</h3>\n\n\n\n<p>Chances are, you won’t always want your buttons and headers right in the middle of an image. That’s why we’ve made it easy to change the vertical and horizontal alignment.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"424\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/carousel-button-position.png\" alt=\"Changing the vertical and horizontal position of headers and buttons on carousel images in SeedProd\" class=\"wp-image-39146\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/carousel-button-position.png 662w, https://www.seedprod.com/wp-content/uploads/2025/03/carousel-button-position-400x256.png 400w, https://www.seedprod.com/wp-content/uploads/2025/03/carousel-button-position-50x32.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>This means you can move the text and button to anywhere you like on the carousel. Just drag the sliders until everything is right where you want it.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"aioseo-make-every-element-work-together\">Make Every Element Work Together</h3>\n\n\n\n<p>You can customize the look of each text and button element to match your website perfectly. Change fonts, adjust sizes, and pick colors that grab attention.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"429\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/carousel-header-font.png\" alt=\"Changing header fonts and colors in SeedProd image carousel block\" class=\"wp-image-39147\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/carousel-header-font.png 662w, https://www.seedprod.com/wp-content/uploads/2025/03/carousel-header-font-400x259.png 400w, https://www.seedprod.com/wp-content/uploads/2025/03/carousel-header-font-50x32.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Plus, add smooth animations to make your content come alive and keep visitors engaged.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"492\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/carousel-animation-effects.gif\" alt=\"Adding animations to headers and buttons in SeedProd\'s image carousel block\" class=\"wp-image-39148\"/></figure>\n\n\n\n<p>If you’re unsure how to make the most of this update, here are some tried and tested ways you can use image carousels to get results for your business:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Show off your products with &#8220;Buy Now&#8221; buttons that turn browsers into buyers</li>\n\n\n\n<li><a href=\"https://www.seedprod.com/how-to-embed-google-reviews-wordpress/\" title=\"How to Embed Google Reviews in WordPress (+ Yelp Reviews)\">Display customer reviews</a> with professional text overlays that build instant trust</li>\n\n\n\n<li>Create portfolio presentations that help you land more clients</li>\n\n\n\n<li>Highlight your services with clear calls-to-action that get more bookings</li>\n\n\n\n<li>Promote special offers with eye-catching headlines that drive sales</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"606\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/testimonial-carousel-800x606.png\" alt=\"Testimonial carousel with book now button\" class=\"wp-image-39153\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/testimonial-carousel-800x606.png 800w, https://www.seedprod.com/wp-content/uploads/2025/03/testimonial-carousel-400x303.png 400w, https://www.seedprod.com/wp-content/uploads/2025/03/testimonial-carousel-768x581.png 768w, https://www.seedprod.com/wp-content/uploads/2025/03/testimonial-carousel-50x38.png 50w, https://www.seedprod.com/wp-content/uploads/2025/03/testimonial-carousel.png 873w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></figure>\n\n\n\n<p>While other WordPress builders make you struggle with settings or charge extra for basic features, our new Image Carousel gives you everything you need in one simple package. No hidden costs, no complexity, <strong>just professional results in minutes</strong>.</p>\n\n\n\n<p>Think about it: How many more conversions could you get with sliders that actually engage your visitors?</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"aioseo-new-industry-specific-website-themes\">New Industry-Specific Website Themes</h2>\n\n\n\n<p>I know how time-consuming it can be to <a href=\"https://www.seedprod.com/how-to-create-a-wordpress-website-for-beginners/\" title=\"How to Create a WordPress Website for Beginners\">start a website from scratch</a>. That&#8217;s why we&#8217;ve also added 15 new professional themes designed specifically for:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Business &amp; Marketing</strong> &#8211; Perfect for agencies, consultants, and service providers</li>\n\n\n\n<li><strong>Health &amp; Wellness</strong> &#8211; Ideal for coaches, therapists, and wellness practitioners</li>\n\n\n\n<li><strong>Entertainment &amp; Travel</strong> &#8211; Great for travel blogs, entertainment venues, and tourist services</li>\n\n\n\n<li><strong>Home Services</strong> &#8211; Designed for contractors, cleaners, and home maintenance pros</li>\n\n\n\n<li><strong>Real Estate</strong> &#8211; Built for realtors, property managers, and real estate investors</li>\n\n\n\n<li><strong>Author</strong> &#8211; Crafted for writers, bloggers, and content creators</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"476\" src=\"https://www.seedprod.com/wp-content/uploads/2025/03/new-industry-specific-WordPress-themes.jpg\" alt=\"New industry specific WordPress themes in SeedProd\" class=\"wp-image-39150\" srcset=\"https://www.seedprod.com/wp-content/uploads/2025/03/new-industry-specific-WordPress-themes.jpg 662w, https://www.seedprod.com/wp-content/uploads/2025/03/new-industry-specific-WordPress-themes-400x288.jpg 400w, https://www.seedprod.com/wp-content/uploads/2025/03/new-industry-specific-WordPress-themes-50x36.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Each theme comes with pre-built pages and sections, making it easy to launch your website faster. Just customize the content, add your branding, and you&#8217;re ready to go.</p>\n\n\n\n<p>And with our new improved Image Carousel block, you can easily enhance any template with engaging, <a href=\"https://www.seedprod.com/create-wordpress-image-carousel/\" title=\"How to Create a WordPress Image Carousel (3 Easy Ways)\">conversion-focused sliders</a> wherever you need them.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"aioseo-create-sliders-that-actually-convert\">Create Sliders That Actually Convert</h2>\n\n\n\n<p>With this update, you can say goodbye to sliders that visitors ignore and hello to more potential leads and customers.</p>\n\n\n\n<p>To see the difference this update can make for your business, update your SeedProd plugin and try it today.</p>\n\n\n\n<p>As always, thank you for being part of the SeedProd community. We&#8217;re committed to making website building easier and more powerful for you.</p>\n\n\n\n<p>John and the SeedProd team.</p>\n\n\n\n<p><strong>P.S. </strong>Don&#8217;t have SeedProd Pro yet? Join over 1 million website owners who trust us to build beautiful WordPress websites without code.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>The post <a href=\"https://www.seedprod.com/announcement-better-image-carousels-industry-themes/\">New in SeedProd: Better Image Carousels + 15 Industry Themes</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:85:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"SeedProd Themes Just Got a Speed Boost: Enjoy Faster Imports\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:52:\"https://www.seedprod.com/announcement-faster-themes/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"https://www.seedprod.com/announcement-faster-themes/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 24 Jun 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:12:\"import theme\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:12:\"website kits\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=36393\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:355:\"<p>Tired of waiting for WordPress themes to load? SeedProd now offers lightning-fast theme imports, so you can build your dream website in minutes.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-faster-themes/\">SeedProd Themes Just Got a Speed Boost: Enjoy Faster Imports</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Stacey Corrin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6325:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"379\" src=\"https://www.seedprod.com/wp-content/uploads/2024/06/seedProd-themes-just-got-a-speed-boost-800x379.png\" class=\"attachment-large size-large wp-post-image\" alt=\"SeedProd Themes Just Got a Speed Boost: Enjoy Faster Imports\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/06/seedProd-themes-just-got-a-speed-boost-800x379.png 800w, https://www.seedprod.com/wp-content/uploads/2024/06/seedProd-themes-just-got-a-speed-boost-400x189.png 400w, https://www.seedprod.com/wp-content/uploads/2024/06/seedProd-themes-just-got-a-speed-boost-768x364.png 768w, https://www.seedprod.com/wp-content/uploads/2024/06/seedProd-themes-just-got-a-speed-boost-50x24.png 50w, https://www.seedprod.com/wp-content/uploads/2024/06/seedProd-themes-just-got-a-speed-boost.png 1444w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></div>|||\n<p>At <a href=\"https://www.seedprod.com\" title=\"SeedProd - Best Drag &amp; Drop WordPress Website Builder\">SeedProd</a>, we listen to your feedback. You told us you love our template kits but want faster imports. We know waiting for templates to load is a major roadblock when creating a website.</p>\n\n\n\n<p>Since speed is one of our top priorities, we&#8217;re excited to announce we&#8217;ve made significant speed improvements to our theme imports, making website creation even <strong>faster</strong> and <strong>easier</strong>.</p>\n\n\n\n<p>First, let’s look at how our previous template imports worked.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Why Did Importing Templates Take Time?</h2>\n\n\n\n<p>In the past, when you imported a template kit, all the image files loaded directly from our servers.</p>\n\n\n\n<p>This process could take a while, especially if you have a slower internet connection or are importing a kit with many large images, such as those in our WooCommerce site kits.</p>\n\n\n\n<p>Here’s an example of how this looked in practice:</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"600\" height=\"395\" src=\"https://www.seedprod.com/wp-content/uploads/2024/06/slow-template-imports.gif\" alt=\"Previous SeedProd site kits were slow to import\" class=\"wp-image-36395\"/></figure>\n\n\n\n<p>We understand how frustrating it is to have this delay in your <a href=\"https://www.seedprod.com/ultimate-launch-checklist-wordpress-website/\" title=\"24 Point Checklist For A Successful WordPress Website Launch\">website launch</a>. It makes it difficult to test different designs quickly or causes you to miss important deadlines.</p>\n\n\n\n<p>We also know this isn&#8217;t ideal for our users, so we set out to find a better way.</p>\n\n\n\n<h2 class=\"wp-block-heading\">How We Made Importing Faster</h2>\n\n\n\n<p>To solve this, we’ve introduced a Content Delivery Network (CDN). It’s like a network of servers spread across the globe, each storing copies of your website&#8217;s images.</p>\n\n\n\n<p>When you <a href=\"https://www.seedprod.com/how-to-export-a-wordpress-theme/\" title=\"How to Export a WordPress Theme (+ Import to Another Site)\">import a template kit</a>, the images now come from the CDN server closest to you. This means you no longer have to wait for images to download slowly from a distant server. Your site is also protected from outages and attacks, as there are multiple servers to handle the load.</p>\n\n\n\n<p>Here’s how importing the same theme from the previous example looks now:</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"436\" src=\"https://www.seedprod.com/wp-content/uploads/2024/06/slow-template-import.gif\" alt=\"SeedProd template kits now import instantly.\" class=\"wp-image-36394\"/></figure>\n\n\n\n<p>As you can see, the import is almost instant!</p>\n\n\n\n<h2 class=\"wp-block-heading\">What Faster Imports Mean For You</h2>\n\n\n\n<p>You&#8217;ll notice a dramatic difference the next time you import a SeedProd template:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Instant Gratification:</strong> Your site kit will be ready to customize in a fraction of the time, allowing you to see your design come to life in the blink of an eye.</li>\n\n\n\n<li><strong>Rapid Prototyping:</strong> Experiment with multiple templates effortlessly and find the perfect fit for your project.</li>\n\n\n\n<li><strong>Lightning-Fast Launches:</strong> Get your website up and running faster than ever before and hit your deadlines with confidence.</li>\n\n\n\n<li><strong>Smoother Workflow:</strong> Enjoy an uninterrupted creative flow without slow imports disrupting your momentum.</li>\n\n\n\n<li><strong>Stress-Free Experience:</strong> No more frustration or impatience – just focus on creating a website you can be proud of.</li>\n</ul>\n\n\n\n<p>This means less waiting, more creating, and faster website launches. We&#8217;ve removed the waiting so you can focus on the fun part &#8211; <a href=\"https://www.seedprod.com/how-to-create-a-wordpress-website-for-beginners/\" title=\"How to Create a WordPress Website for Beginners\">designing a stunning website</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Give It a Try Today</h3>\n\n\n\n<p>Experience the speed difference for yourself!</p>\n\n\n\n<p>Import a template kit today and see how fast you can create your dream website with SeedProd. New to SeedProd? Explore our library of 150+ template kits and start building your website in minutes.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>\n\n\n\n<p>If you have questions or feedback, don’t hesitate to contact our <a href=\"https://www.seedprod.com/contact/\" title=\"Contact SeedProd\">customer support team</a>. And as always, thank you for helping to make SeedProd the <a href=\"https://www.seedprod.com/\" title=\"SeedProd  - Best Drag and Drop WordPress Website Builder\">best drag-and-drop WordPress website builder</a>.</p>The post <a href=\"https://www.seedprod.com/announcement-faster-themes/\">SeedProd Themes Just Got a Speed Boost: Enjoy Faster Imports</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://www.seedprod.com/announcement-faster-themes/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:72:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:63:\"Build Websites Faster with New Theme Kits &amp; Dynamic Content\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"https://www.seedprod.com/announcement-site-kits-dynamic-tags/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 22 Apr 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:6:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:12:\"dynamic tags\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:12:\"dynamic text\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:12:\"website kits\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=35125\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:373:\"<p>We just released a major update with new website template kits and Dynamic Tags to help you personalize your website and save time. Read on to learn more.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-site-kits-dynamic-tags/\">Build Websites Faster with New Theme Kits & Dynamic Content</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Stacey Corrin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:14944:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"379\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/build-websites-faster-with-new-theme-kits-dynamic-content-800x379.png\" class=\"attachment-large size-large wp-post-image\" alt=\"Build Websites Faster with New Theme Kits &amp; Dynamic Content\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/build-websites-faster-with-new-theme-kits-dynamic-content-800x379.png 800w, https://www.seedprod.com/wp-content/uploads/2024/04/build-websites-faster-with-new-theme-kits-dynamic-content-400x189.png 400w, https://www.seedprod.com/wp-content/uploads/2024/04/build-websites-faster-with-new-theme-kits-dynamic-content-768x364.png 768w, https://www.seedprod.com/wp-content/uploads/2024/04/build-websites-faster-with-new-theme-kits-dynamic-content-50x24.png 50w, https://www.seedprod.com/wp-content/uploads/2024/04/build-websites-faster-with-new-theme-kits-dynamic-content.png 1444w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></div>|||\n<p>We&#8217;re excited to announce a major SeedProd update packed with time-saving features and powerful ways to personalize your website. Get started quickly with three new website template kits and effortlessly pull in dynamic WordPress content using our new Dynamic Tags.</p>\n\n\n\n<p>Check out the quick video overview below if you&#8217;re short on time. Or, keep reading for a closer look at what&#8217;s new.&nbsp;</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-responsive  embed-responsive-16by9\"><iframe loading=\"lazy\" class=\"embed-responsive-item\"   title=\"NEW! WordPress Theme Kits &amp; Dynamic Tags...\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/PnDtovOVCPQ?feature=oembed&enablejsapi=1\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe></div>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Launch Your Website Faster with New Theme Kits</h2>\n\n\n\n<p>SeedProd&#8217;s <a href=\"https://www.seedprod.com/templates/\" title=\"SeedProd Website Template Kits\">website template kits</a> provide a professional, ready-to-use foundation for your website. Save hours of design time by choosing a pre-made kit that aligns with your industry and style.</p>\n\n\n\n<p>With over 160+ kits available, we&#8217;re thrilled to introduce 3 brand-new additions:</p>\n\n\n\n<h3 class=\"wp-block-heading\">Car Maintenance Website</h3>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"384\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/car-maintenance-website-kit.jpg\" alt=\"SeedProd car maintenance website kit\" class=\"wp-image-35127\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/car-maintenance-website-kit.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/04/car-maintenance-website-kit-400x232.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/04/car-maintenance-website-kit-50x29.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>This modern, multi-page theme is perfect for businesses in the vehicle service industry. Its clean, polished aesthetic is suitable for virtually any website, while a well-structured layout makes it a breeze for users to navigate and find information.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"378\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/car-mainteance-site-section.jpg\" alt=\"Car maintenance website kit sections\" class=\"wp-image-35128\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/car-mainteance-site-section.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/04/car-mainteance-site-section-400x228.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/04/car-mainteance-site-section-50x29.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>With a mobile-friendly design and the ability to fully customize every element, you can easily adapt it to match your brand.</p>\n\n\n\n<p>Pages included in this site kit are Home, Services, About, Contact, and Blog.&nbsp;<a href=\"https://www.seedprod.com/templates-preview/?theme_id=46925\" title=\"Preview Car Maintenance Website Kit\">Preview it here</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Laundry Services Website</h3>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"380\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-kit.jpg\" alt=\"SeedProd laundry services website template kit\" class=\"wp-image-35129\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-kit.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-kit-400x230.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-kit-50x29.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Looking to give your laundry or dry cleaning business a modern, polished online presence? This site kit has a clean, user-friendly layout that makes it easy for customers to find what they need.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"340\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-section.jpg\" alt=\"Laundry services website kit section\" class=\"wp-image-35130\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-section.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-section-400x205.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/04/laundry-services-website-section-50x26.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>It covers all the essential sections, from a captivating header to a spacious main area to show your services and a footer packed with your contact details, social media links, and anything else your customers need.</p>\n\n\n\n<p>Pages included in this site kit are Home, Services, About, Contact, and Blog.&nbsp;<a href=\"https://www.seedprod.com/templates-preview/?theme_id=46144\" title=\"Preview Laundry Services Website Kit\">Preview it here</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Photography Website</h3>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"396\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-kit.jpg\" alt=\"SeedProd photography website template kit\" class=\"wp-image-35131\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-kit.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-kit-400x239.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-kit-50x30.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Need a <a href=\"https://www.seedprod.com/how-to-create-a-photography-website/\" title=\"How to Create a Photography Website in WordPress 2024\">photography portfolio</a> that wows potential clients? This kit features a clean, minimalist look that puts your images front and center.&nbsp;</p>\n\n\n\n<p>With a sleek, grid-style gallery, it’s super easy for visitors to explore your work. Beyond the gallery, you&#8217;ll find striking sections perfect for showing your services, sharing client testimonials, and offering a glimpse into your business story.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"318\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-section.jpg\" alt=\"Photography website kit section\" class=\"wp-image-35132\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-section.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-section-400x192.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/04/photography-website-section-50x24.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Rounding out the design is a modern footer with a persuasive call to action, contact details, and helpful navigation links.</p>\n\n\n\n<p>This site kit includes Home, Projects, Services, and Contact pages.&nbsp;<a href=\"https://www.seedprod.com/templates-preview/?theme_id=46730\" title=\"Preview Photography Website Kit\">Preview it here</a>.</p>\n\n\n\n<p>Each of these new themes works seamlessly with <strong>Dynamic Tags</strong>, another exciting new feature we&#8217;re thrilled to introduce.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Personalize Your Content with Dynamic Tags</h2>\n\n\n\n<p>Take your content to the next level with our brand-new Dynamic Tags feature (available for <a href=\"https://www.seedprod.com/pricing/\" title=\"SeedProd Pro Pricing\">SeedProd Pro</a> users). These versatile placeholders automatically pull in content from different areas of your WordPress website.</p>\n\n\n\n<p>Here&#8217;s how it works:</p>\n\n\n\n<p>Simply click the new &#8220;Insert Dynamic Tags&#8221; icon in any of our Standard blocks.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"453\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-tags.png\" alt=\"Insert dynamic tags in SeedProd website builder\" class=\"wp-image-35133\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-tags.png 662w, https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-tags-400x274.png 400w, https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-tags-50x34.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Choose from over 25 tags to easily display post data, author information, comments, and more.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"434\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/add-dynamic-tags.png\" alt=\"Select a type of Dynamic tag to add to your WordPress website\" class=\"wp-image-35134\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/add-dynamic-tags.png 662w, https://www.seedprod.com/wp-content/uploads/2024/04/add-dynamic-tags-400x262.png 400w, https://www.seedprod.com/wp-content/uploads/2024/04/add-dynamic-tags-50x33.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>For example, automatically display the number of comments on a blog post and link directly to the comments section to boost engagement.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"642\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/comments-number-dynamic-tags.png\" alt=\"Settings for Comments Number dynamic tags\" class=\"wp-image-35135\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/comments-number-dynamic-tags.png 662w, https://www.seedprod.com/wp-content/uploads/2024/04/comments-number-dynamic-tags-400x388.png 400w, https://www.seedprod.com/wp-content/uploads/2024/04/comments-number-dynamic-tags-50x48.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>After saving your changes, it&#8217;ll look something like this:</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"658\" height=\"449\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/comment-number-dynamic-tag-examole.gif\" alt=\"Example of comment number with link to comments dynamic tag\" class=\"wp-image-35136\"/></figure>\n\n\n\n<p>Here are some more ways to use Dynamic Tags:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Boost author profiles:</strong>&nbsp;Automatically display bios, website links, and social media with &#8220;Author Info&#8221; tags.</li>\n\n\n\n<li><strong>User-generated content:&nbsp;</strong>Easily showcase user-generated content in dynamic galleries using &#8220;Featured Image,&#8221; &#8220;User Info,&#8221; and &#8220;Post Title&#8221; tags.</li>\n\n\n\n<li><strong>Custom Footers</strong>: <a href=\"https://www.seedprod.com/how-to-edit-footer-in-wordpress/\" title=\"How to Edit Footer in WordPress (6 Easy Methods)\">Create custom footers</a> that stay up-to-date – automatically display your site title, logo, tagline, and copyright notices.</li>\n</ul>\n\n\n\n<p>You&#8217;ll also find a new dedicated Dynamic Text icon inside many of SeedProd&#8217;s blocks, making it a cinch to add personalized dates, times, and custom query parameters to your content.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"433\" src=\"https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-text.jpg\" alt=\"Insert dynamic text in SeedProd website builder\" class=\"wp-image-35137\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-text.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-text-400x262.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/04/insert-dynamic-text-50x33.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Update Your SeedProd Plugin Today</h2>\n\n\n\n<p>Ready to dive in and try these new features? Here&#8217;s how:</p>\n\n\n\n<p>Make sure you have the latest version of SeedProd installed – this is where you&#8217;ll find the new theme kits and the Dynamic Tags feature. Then, get creative with Dynamic Tags and see how they can take your website to the next level.</p>\n\n\n\n<p>If you’re new to SeedProd, there’s never been a better time to try our best features. Get started with SeedPod Pro and try this update today.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>\n\n\n\n<p>Of course, if you have any questions along the way, our friendly&nbsp;<a href=\"https://www.seedprod.com/contact/\" title=\"Contact SeedProd\">customer support team</a>&nbsp;is here for you.</p>\n\n\n\n<p>We truly appreciate your support and all the fantastic feedback you share. It helps us make SeedProd the&nbsp;<a href=\"https://www.seedprod.com/\" title=\"SeedProd - Best Drag-and-Drop WordPress Website Builder\">best WordPress website builder</a>&nbsp;out there.</p>\n\n\n\n<p>Let&#8217;s keep building amazing things together.</p>The post <a href=\"https://www.seedprod.com/announcement-site-kits-dynamic-tags/\">Build Websites Faster with New Theme Kits & Dynamic Content</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:69:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"Introducing AI Image Creation: Say ‘Goodbye’ to Stock Photos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://www.seedprod.com/announcement-ai-image-creation/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 25 Mar 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:17:\"ai image creation\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:20:\"ai WordPress builder\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=34456\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:374:\"<p>Unleash your creativity. SeedProd AI now generates unique images to power your website &#038; marketing. Design like a pro with SeedProd AI image creation.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-ai-image-creation/\">Introducing AI Image Creation: Say ‘Goodbye’ to Stock Photos</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Stacey Corrin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:18984:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"379\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/introducing-ai-image-creation-800x379.png\" class=\"attachment-large size-large wp-post-image\" alt=\"Introducing AI Image Creation: Say ‘Goodbye’ to Stock Photos\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/introducing-ai-image-creation-800x379.png 800w, https://www.seedprod.com/wp-content/uploads/2024/03/introducing-ai-image-creation-400x189.png 400w, https://www.seedprod.com/wp-content/uploads/2024/03/introducing-ai-image-creation-768x364.png 768w, https://www.seedprod.com/wp-content/uploads/2024/03/introducing-ai-image-creation-50x24.png 50w, https://www.seedprod.com/wp-content/uploads/2024/03/introducing-ai-image-creation.png 1083w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></div>|||\n<p>Hot off the heels of our AI writing assistant, we’re excited to announce AI Image generation for SeedProd. In version 6.17, you can turn your ideas into unique images right inside our drag-and-drop page builder.</p>\n\n\n\n<p>Say farewell to generic stock photos and welcome to creativity with a few clicks.</p>\n\n\n\n<p>If you’re in a hurry, here’s a quick overview of SeedProd’s new Image AI:</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-responsive  embed-responsive-16by9\"><iframe loading=\"lazy\" class=\"embed-responsive-item\"   title=\"NEW AI Images! Say &#039;Goodbye&#039; to Stock Photos...\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/SL2-gXlDeE4?feature=oembed&enablejsapi=1\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe></div>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Create Original Images for Your Website with AI</h2>\n\n\n\n<p>Studies show that&nbsp;<a href=\"https://venngage.com/blog/visual-content-marketing-statistics/#2024-stats\" target=\"_blank\" rel=\"noopener nofollow\" title=\"Visual Content Marketing Statistics\">unique pictures do better</a>&nbsp;than boring stock photos, and we hear you. That&#8217;s why we added a new feature that allows you to make your own images.</p>\n\n\n\n<p>SeedProd now uses DALL-E, a text-to-image model, to help you create unique images that fit your brand.</p>\n\n\n\n<p>Need a beach scene for your travel website? Describe it, and AI will generate it automatically.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"510\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/generate-image-ai.jpg\" alt=\"Screenshot of SeedProd AI image generation interface with a backdrop of a serene beach scene at sunset. The interface has a red-bordered box titled \'Generate image with AI\' containing a text input field and a list of suggested prompts such as generating a futuristic cityscape or visualizing a peaceful beach scene. The \'Visualize a peaceful beach scene with palm trees and a sunset\' prompt is highlighted. Below the prompts are buttons for \'Generate Images\' and \'Cancel\'.\" class=\"wp-image-34457\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/generate-image-ai.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/03/generate-image-ai-400x308.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/03/generate-image-ai-50x39.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>This isn&#8217;t about replacing artists but making cool images easier for everyone. If you can&#8217;t afford a designer, image AI can help by creating high-quality images at a lower cost.</p>\n\n\n\n<p>Instead of replacing creativity, it helps you enhance your own.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Instantly Bring Your Ideas to Life</h3>\n\n\n\n<p>Forget spending hours searching for the right picture. Now, just type what you need into the Image Generator, and watch as it quickly turns your ideas into real images.</p>\n\n\n\n<p>Here’s how it works:</p>\n\n\n\n<p>Drag an Image block onto your page and click the ‘Add with AI’ button in the block settings on the left.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"352\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/add-image-with-ai-seedprod.png\" alt=\"Screenshot of SeedProd editing interface showing an \'Image\' block with an option to \'Add with AI\'. An arrow points to the button. Below are two choices to \'Choose New Image\' with options to \'Use Your Own Image\' or \'Use a Stock Image\'. To the right are \'Block Settings\' with various icons for customization.\" class=\"wp-image-34458\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/add-image-with-ai-seedprod.png 662w, https://www.seedprod.com/wp-content/uploads/2024/03/add-image-with-ai-seedprod-400x213.png 400w, https://www.seedprod.com/wp-content/uploads/2024/03/add-image-with-ai-seedprod-50x27.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Next, describe the image you want to create and click the ‘Generate Images’ button. After a few seconds, SeedProd will display the image. Then, you can add it to your website by clicking Insert.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"352\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/generated-ai-image-seedprod.png\" alt=\"Screenshot of SeedProd AI image generation interface with the text field filled with \'A closeup product shot of a delicious meal\'. Below the text field are \'Generate Images\' and \'Cancel\' buttons. On the right, a generated image of a meal is displayed, featuring a dish with what appears to be roasted vegetables garnished with herbs, suggesting a successful image generation.\" class=\"wp-image-34459\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/generated-ai-image-seedprod.png 662w, https://www.seedprod.com/wp-content/uploads/2024/03/generated-ai-image-seedprod-400x213.png 400w, https://www.seedprod.com/wp-content/uploads/2024/03/generated-ai-image-seedprod-50x27.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Need a specific scene or an abstract design? Just describe it, and AI will handle the rest. It&#8217;s about making your website look good and feel uniquely yours with a few clicks.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"351\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-example.png\" alt=\"A promotional image featuring a close-up of a delicious rice bowl. The bowl is filled with rice, grilled vegetables, and herbs. To the right is text that reads \'Delicious Rice Bowls\' followed by a description emphasizing that the rice bowls are made fresh daily with locally sourced produce, high quality and flavor, and a variety of ingredients, offering a satisfying meal for customers.\" class=\"wp-image-34460\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-example.png 662w, https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-example-400x212.png 400w, https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-example-50x27.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Tailor-Made Images: Edit Without Limits</h3>\n\n\n\n<p>Our AI Image generator doesn’t just create images; you can also fine-tune them. Once your image is on the page, click the ‘Edit with AI’ button, and the magic begins.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"450\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/edit-ai-image-seedprod.jpg\" alt=\"Screenshot of SeedProd AI image editing interface with options \'Generate with a prompt\', \'Variations\', \'Edit Image\', and \'Cancel\' on the left side, and a high-quality image of a rice bowl with vegetables on the right. An arrow points to the \'Edit Image\' option.\" class=\"wp-image-34461\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/edit-ai-image-seedprod.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/03/edit-ai-image-seedprod-400x272.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/03/edit-ai-image-seedprod-50x34.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Select a specific area of the illustration and add the changes you want to your original prompt.</p>\n\n\n\n<p>Let’s say you asked AI to create an image of a cat playing with a ball. In the editor, you can select the ball and change the prompt to a cat playing with a toy car instead.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"436\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/customize-ai-image-seedprod.jpg\" alt=\"Screenshot of SeedProd AI image editing interface with text input reading \'a cat playing with a toy car on a sofa.\' A main image shows an orange cat looking towards the camera with a section erased, while a smaller inset image shows the same cat with a toy car, highlighted in a red box to indicate editing.\" class=\"wp-image-34462\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/customize-ai-image-seedprod.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/03/customize-ai-image-seedprod-400x263.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/03/customize-ai-image-seedprod-50x33.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Whether you’re adding the finishing touches or reimagining an entire image, SeedProd AI makes it easy. The result? A cohesive and professional appearance for your website.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Mix, Match, and Marvel at Your Creations</h3>\n\n\n\n<p>Why stop at one original image when you can generate several?</p>\n\n\n\n<p>With the ‘Variations’ setting, you can try out different ideas and generate a set of unique graphics. It&#8217;s perfect for when you need many images with a similar theme but still want them to stand out on their own.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"235\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-variations-seedprod.jpg\" alt=\"SeedProd interface for generating variations of an image, showing two similar images of a vegetable rice bowl. Each image has an \'Insert\' button below it. At the top left, there are \'Back\' and \'Cancel\' buttons.\" class=\"wp-image-34463\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-variations-seedprod.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-variations-seedprod-400x142.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/03/ai-image-variations-seedprod-50x18.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Try different prompts to experiment with styles. You could create product shots at different angles or background images for other sections of your site with the same theme.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"401\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/variations-ai-image.jpg\" alt=\"Two background image variations of a lavish feast laid out on tables in an elegant dining room, each image with an \'Insert\' button below it.\" class=\"wp-image-34464\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/variations-ai-image.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/03/variations-ai-image-400x242.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/03/variations-ai-image-50x30.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Whatever your idea, image variations help keep your website interesting while telling your brand’s story.</p>\n\n\n\n<h2 class=\"wp-block-heading\">New Site Kits &amp; Blocks</h2>\n\n\n\n<p>Along with <a href=\"https://www.seedprod.com/how-to-use-ai-to-generate-images/\" title=\"How to Use AI to Generate Images on Your WordPress Website\">AI image creation</a>, we’ve released 9 new website kits. These are perfect for different niches, like portfolios, agencies, real estate, yoga, and travel.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"288\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/seedprod-site-kits-march-24.jpg\" alt=\"Three SeedProd website templates displayed side by side. The left template is for \'Cloudcraft SaaS Web App Theme\' focused on design and deployment, the middle is a \'Fintech SaaS Web App Theme\' for streamlining finances, and the right is an \'Outdoor Adventure Theme\' for adventure travel.\" class=\"wp-image-34465\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/seedprod-site-kits-march-24.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/03/seedprod-site-kits-march-24-400x174.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/03/seedprod-site-kits-march-24-50x22.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Each kit is a great starting point for adding your own touch and is ready to customize with unique AI-generated images. Choose any demo image from the template, and use AI to create your own.</p>\n\n\n\n<p>We’ve also added a new Push Notification block to our block library for paid SeedProd plans. With this, you can easily install PushEngage, a popular push notification software, directly on your WordPress site.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"309\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-block-seedprod.png\" alt=\"User interface of SeedProd website builder showing \'Design\' and \'Connect\' tabs, with \'Push Notifications\' block highlighted. A notification \'PushEngage Installed and Activated\' is shown on the website preview.\" class=\"wp-image-34466\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-block-seedprod.png 662w, https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-block-seedprod-400x187.png 400w, https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-block-seedprod-50x23.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>The block doesn’t affect the overall design of your page. However, after configuring the PushEngage plugin, visitors to the page will see a popup inviting them to subscribe to your notifications.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"154\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-optin.png\" alt=\"Popup message on a website with the  text \'This website would like to send push notifications\' with \'Allow\' and \'Close\' buttons.\" class=\"wp-image-34467\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-optin.png 662w, https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-optin-400x93.png 400w, https://www.seedprod.com/wp-content/uploads/2024/03/push-notification-optin-50x12.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>We added this feature to make integrating with PushEngage much easier. It doesn’t require adding additional code snippets and lets you reap the benefits of browser notifications.</p>\n\n\n\n<p>For example, you can use push notifications to:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Get news out fast:</strong>&nbsp;Deliver news and updates straight to visitors&#8217; screens, even if they&#8217;re not on your site.</li>\n\n\n\n<li><strong>Bring people back:</strong>&nbsp;Remind folks who visited your site about cool stuff they might have missed.</li>\n\n\n\n<li><strong>Drive clicks and sales:</strong>&nbsp;Lure visitors back to your site where they might buy something or take another desired action.</li>\n\n\n\n<li><strong>Personalize messages:</strong>&nbsp;Tailor your notifications to what users like or what they look at on your site.</li>\n\n\n\n<li><strong>Keep them coming back</strong>: Create a buzz or sense of urgency to encourage people to visit your site more often.</li>\n</ul>\n\n\n\n<p>Last but not least, is an update to the Headline block available to free and paid users. Now, you can add a custom link to any headline and set it to open in a new tab or window.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"546\" src=\"https://www.seedprod.com/wp-content/uploads/2024/03/headline-link-seedprod.png\" alt=\"Screenshot SeedProd editing tool focusing on a \'Headline\' block with option to add a link, highlighted by a red arrow pointing to the link icon.\" class=\"wp-image-34468\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/03/headline-link-seedprod.png 662w, https://www.seedprod.com/wp-content/uploads/2024/03/headline-link-seedprod-400x330.png 400w, https://www.seedprod.com/wp-content/uploads/2024/03/headline-link-seedprod-50x41.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>With this addition, it’s easier to link to other pages so readers can find what they need faster. Plus, linking to relevant content sends positive signals to search engines.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Unchain Your Imagination with AI Images</h2>\n\n\n\n<p>SeedProd’s AI image generator is part of our AI addon for premium users, which uses a credit system. For each image you generate, you’ll use 33 AI credits.</p>\n\n\n\n<p>To give it a go, visit your SeedProd dashboard and click the option to buy credits.</p>\n\n\n\n<p>If you&#8217;re new to SeedProd, there’s never been a better time to try our best features. Get started with SeedPod Pro and try AI Image creation today.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>\n\n\n\n<p>If you have questions or feedback about this feature, don&#8217;t hesitate to&nbsp;<a href=\"https://www.seedprod.com/contact/\" title=\"Contact SeedProd\">contact our customer support team</a>. We&#8217;re always ready to walk you through what you need.As always, thank you for helping to make SeedProd the&nbsp;<a href=\"https://www.seedprod.com/\" title=\"SeedProd Drag-and-Drop WordPress Website Builder\">best drag-and-drop WordPress website builder</a>.</p>The post <a href=\"https://www.seedprod.com/announcement-ai-image-creation/\">Introducing AI Image Creation: Say ‘Goodbye’ to Stock Photos</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:69:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"Introducing SeedProd AI Assistant for Effortless Content Creation\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://www.seedprod.com/announcement-ai-writing-assistant/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 26 Feb 2024 13:00:44 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:15:\"ai landing page\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:23:\"artificial intelligence\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=33453\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:379:\"<p>Introducing SeedProd\'s new AI writing assistant. Learn how to generate high-quality text for any WordPress page or web design project using the power of AI.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-ai-writing-assistant/\">Introducing SeedProd AI Assistant for Effortless Content Creation</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Stacey Corrin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:15260:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"379\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/introducing-seedprod-ai-writting-assistant-800x379.png\" class=\"attachment-large size-large wp-post-image\" alt=\"Announcement SeedProd AI Writing Assistant\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/introducing-seedprod-ai-writting-assistant-800x379.png 800w, https://www.seedprod.com/wp-content/uploads/2024/02/introducing-seedprod-ai-writting-assistant-400x189.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/introducing-seedprod-ai-writting-assistant-768x364.png 768w, https://www.seedprod.com/wp-content/uploads/2024/02/introducing-seedprod-ai-writting-assistant-50x24.png 50w, https://www.seedprod.com/wp-content/uploads/2024/02/introducing-seedprod-ai-writting-assistant.png 1444w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></div>|||\n<p>The year is in full swing, and to keep the momentum going, we’re announcing one of the most exciting updates to our plugin.</p>\n\n\n\n<p>Introducing AI text generation with <a href=\"https://www.seedprod.com\" title=\"SeedProd - Best Drag &amp; Drop WordPress Website Builder\">SeedProd’s</a> AI writing assistant add-on.</p>\n\n\n\n<p>Generate catchy headlines, craft clear descriptions, and write engaging content &#8211; all with a few clicks. Our new AI removes writer&#8217;s block, leaving you free to focus on what matters: building a website that converts.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-responsive  embed-responsive-16by9\"><iframe loading=\"lazy\" class=\"embed-responsive-item\"   title=\"NEW! SeedProd AI Writing Assistant For EASY Content Creation!\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/gzCYMtEju4c?feature=oembed&enablejsapi=1\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe></div>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">AI-Powered Website Copy</h2>\n\n\n\n<p>Remember agonizing over every sentence, rewriting headlines endlessly, and wishing you could spend less time writing and more time building? With SeedProd’s <a href=\"https://www.seedprod.com/ai-wordpress-builders/\" title=\"3 Best AI WordPress Builders (+8 Content Tools) for 2024\">AI website builder</a> and writing assistant, those days are gone.</p>\n\n\n\n<p>Our AI assistant lets you quickly generate headlines and body text for your site, streamlining the content creation process for any design project.</p>\n\n\n\n<p>Let’s take a look at how it works.</p>\n\n\n\n<p>Click any Headline or Text block from the drag-and-drop page builder to open its settings. In the left-hand sidebar, click the&nbsp;<strong>Generate AI Text</strong>&nbsp;button.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"354\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/generate-ai-text-1.png\" alt=\"Generate AI text in SeedProd page builder\" class=\"wp-image-33455\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/generate-ai-text-1.png 662w, https://www.seedprod.com/wp-content/uploads/2024/02/generate-ai-text-1-400x214.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/generate-ai-text-1-50x27.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Next, you’ll see a popup asking you to describe your text. Click the suggested prompts to make this easier, or type your own in the text field, then click the&nbsp;<strong>Generate Text</strong>&nbsp;button.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"521\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/write-with-ai.png\" alt=\"Describe and Generate Text with AI in SeedProd page builder\" class=\"wp-image-33456\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/write-with-ai.png 662w, https://www.seedprod.com/wp-content/uploads/2024/02/write-with-ai-400x315.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/write-with-ai-50x39.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>It takes just a few seconds for the AI to create your content. If you’re happy with the result, click&nbsp;<strong>Insert</strong>&nbsp;to add it to your page.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"383\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/add-ai-text-wordpress.gif\" alt=\"Generate and insert AI text in SeedProd page builder\" class=\"wp-image-33457\"/></figure>\n\n\n\n<p>You can go from a blank page to eye-catching content that resonates with your audience in minutes.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Strengthen Your Brand’s Voice</h3>\n\n\n\n<p>Maintaining a consistent voice and style across your website is crucial for building trust and recognition. But let&#8217;s be honest, creating the perfect content for every page is time-consuming and challenging.</p>\n\n\n\n<p>You can use SeedProd&#8217;s AI assistant to select any text on your page and adjust its tone, style, and formality to match your brand’s voice.&nbsp;</p>\n\n\n\n<p>Whether it’s a professional tone for your landing page or conversational About page text, switching up your writing style is simple.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"531\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/ai-text-tone.png\" alt=\"Change the tone of AI generated text in SeedProd\" class=\"wp-image-33458\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/ai-text-tone.png 662w, https://www.seedprod.com/wp-content/uploads/2024/02/ai-text-tone-400x321.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/ai-text-tone-50x40.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Click the Choose Tone dropdown and select from 30 styles running from funny and excited, to professional and serious.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Optimize Your Headlines</h3>\n\n\n\n<p>According to WPBeginner, only&nbsp;<a href=\"https://www.wpbeginner.com/opinion/anatomy-of-a-high-converting-landing-page/\" target=\"_blank\" rel=\"noopener\" title=\"Anatomy of a High Converting Landing Page\">20% of visitors</a>&nbsp;read your landing page’s full text, but 80% will read the full title. This makes writing the perfect headline just as important.</p>\n\n\n\n<p>Besides generating engaging content, you can use our AI assistant to shorten any text.</p>\n\n\n\n<p>For example, you can take a long, complicated headline and cut it down with a single click, making it instantly more readable and user-friendly.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"570\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/shorter-ai-text.png\" alt=\"Make AI generated text shorter in SeedProd\" class=\"wp-image-33459\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/shorter-ai-text.png 662w, https://www.seedprod.com/wp-content/uploads/2024/02/shorter-ai-text-400x344.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/shorter-ai-text-50x43.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Or you can generate several headlines and test each one to see which resonates the most with your audience.</p>\n\n\n\n<p>It’s just as easy to improve less detailed content by adding more information and context. Click the ‘Make it Longer’ button, and you’ll have relevant text on any topic in a few seconds.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Translate Your Site into Multiple Languages</h3>\n\n\n\n<p>In addition to content generation, SeedProd&#8217;s AI assistant makes it easy to translate your website into multiple languages. This makes it much easier to reach diverse audiences without paying for expensive translation services or translating content yourself.</p>\n\n\n\n<p>From any headline or text block, click the <strong>Choose Language</strong> dropdown and select from over 50+ languages to translate your content automatically.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"560\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/translate-ai-text.png\" alt=\"Translate AI generated text into different languages in SeedProd\" class=\"wp-image-33460\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/translate-ai-text.png 662w, https://www.seedprod.com/wp-content/uploads/2024/02/translate-ai-text-400x338.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/translate-ai-text-50x42.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>For example, if your website sells products or services to global audiences, you can translate the content to reach those users. You can do the same for FAQs so customers can find answers and resolve issues in their preferred language.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Create Lightning Fast Placeholder Text&nbsp;</h3>\n\n\n\n<p>We understand that speed and quality are essential for web designers. You want to get projects off the ground fast while providing the best results to your clients.</p>\n\n\n\n<p>Our AI assistant can help by allowing you to fill your projects with relevant placeholder text. It’s an excellent way to help clients understand each page&#8217;s layout, flow, and purpose while saving you time and effort.</p>\n\n\n\n<p>You can also use it to create reusable templates. Instead of relying on generic lorem ipsum text, you can fill your templates with niche-related content.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"312\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/ai-placeholder-text.jpg\" alt=\"Example of replacing lorem ipsum placeholder text with AI generated text\" class=\"wp-image-33461\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/ai-placeholder-text.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/02/ai-placeholder-text-400x189.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/02/ai-placeholder-text-50x24.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>For instance, if you’re building a website template for <a href=\"https://www.seedprod.com/how-to-create-a-real-estate-website/\" title=\"How to Create a Real Estate Website in WordPress\">real estate projects</a>, you can quickly generate content related to that industry. Or, if it’s an eCommerce site, you can fill it with product descriptions that take seconds to generate.</p>\n\n\n\n<p>We even put together this guide on <a href=\"https://www.seedprod.com/ai-landing-page/\" title=\"How to Create an AI Landing Page in WordPress Step-by-Step\">how to create an AI landing page</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">More Site Kits &amp; Bug Fixes</h2>\n\n\n\n<p>Besides launching our AI writing assistant, we’ve also been hard at work improving the features you already know and love.</p>\n\n\n\n<p>We’ve added 10 new site kits to our <a href=\"https://www.seedprod.com/templates/\" title=\"SeedProd Templates Library\">themes library</a> for agencies, freelancers, magazines, and even medical websites.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"289\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/feb-24-site-kits.jpg\" alt=\"SeedProd website template kits released in February 2024\" class=\"wp-image-33462\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/feb-24-site-kits.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/02/feb-24-site-kits-400x175.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/02/feb-24-site-kits-50x22.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>With this release of SeedProd, we’ve also introduced fixes to product archive features, gallery and carousel images, and LinkedIn URLs in our social sharing block.</p>\n\n\n\n<p>For all the details, please see our&nbsp;<a class=\"heroickb_exit_link\" href=\"?hkb-redirect&#038;nonce=8ae63e5780&#038;check=7t1rp&#038;redirect=https%3A%2F%2Fwww.seedprod.com%2Fdocs%2Fchangelog%2F&#038;otype=unknown&#038;oid=0&#038;source=block-content\" title=\"SeedProd Changelog\">changelog</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Get Started With SeedProd AI</h3>\n\n\n\n<p>SeedProd’s AI writing assistant is available as a <strong>separate add-on</strong> when you subscribe to any of our premium plans.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"270\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-addon-1.png\" alt=\"SeedProd AI Addon at checkout\" class=\"wp-image-33736\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-addon-1.png 662w, https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-addon-1-400x163.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-addon-1-50x20.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Users with a paid plan can upgrade by visiting your SeedProd dashboard.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"160\" src=\"https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-upgrade.png\" alt=\"SeedProd AI Addon upgrade\" class=\"wp-image-33737\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-upgrade.png 662w, https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-upgrade-400x97.png 400w, https://www.seedprod.com/wp-content/uploads/2024/02/seedprod-ai-upgrade-50x12.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>You can access all new site kits and bug fixes as soon as you update your plugin to the latest version.</p>\n\n\n\n<p>If you’re new to SeedProd, now is the best time to upgrade to SeedProd Pro and explore everything it offers.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>\n\n\n\n<p>And if you have questions, don’t hesitate to&nbsp;<a href=\"https://www.seedprod.com/contact/\" title=\"Contact SeedProd\">get in touch</a>&nbsp;with our support team or leave a comment on this post. We’re always ready to help you get the most out of SeedProd, so please keep the suggestions and feedback coming.</p>\n\n\n\n<p>As always, thank you for helping to make SeedProd the&nbsp;<a href=\"https://www.seedprod.com/\" title=\"SeedProd - Best Drag-and-drop WordPress Website Builder\">best WordPress website builder</a>.</p>The post <a href=\"https://www.seedprod.com/announcement-ai-writing-assistant/\">Introducing SeedProd AI Assistant for Effortless Content Creation</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:72:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"Introducing Tablet Breakpoints, Videos Teasers + More\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://www.seedprod.com/announcement-tablet-breakpoint-teaser-video/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 09 Jan 2024 13:01:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:6:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:12:\"translations\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:11:\"video block\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:13:\"video teasers\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=32134\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:380:\"<p>We\'re thrilled to announce several new features for SeedProd, including tablet breakpoints, video teasers, more website kits, and 10 new language translations.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-tablet-breakpoint-teaser-video/\">Introducing Tablet Breakpoints, Videos Teasers + More</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Turner John\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:14815:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"379\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/tablet-break-point-800x379.png\" class=\"attachment-large size-large wp-post-image\" alt=\"Introducing Tablet Breakpoints for SeedProd\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/tablet-break-point-800x379.png 800w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-break-point-400x189.png 400w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-break-point-768x364.png 768w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-break-point-50x24.png 50w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-break-point.png 1444w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></div>|||\n<p>It’s a new year, and we&#8217;re excited to kick it off with some fresh updates for SeedProd that provide even more flexibility as you design your websites. Today, we’re pleased to announce tablet display options, teaser videos, and a host of new site kits for various niches.</p>\n\n\n\n<p>If you’re in a hurry, check out the announcement video below for a quick overview:</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-responsive  embed-responsive-16by9\"><iframe loading=\"lazy\" class=\"embed-responsive-item\"   title=\"NEW! Introducing Tablet Breakpoints, Teaser Videos, New Site Kits, And More!\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/uxxL1roAhC4?feature=oembed&enablejsapi=1\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe></div>\n</div></figure>\n\n\n\n<p>Otherwise, keep reading for the full details of our new year update.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Control Your Web Design on Tablets</h2>\n\n\n\n<p>Our first new feature is something a lot of users have asked for:&nbsp;<strong>Tablet Breakpoints</strong>.</p>\n\n\n\n<p>A breakpoint is a signal that tells your site how to adjust its layout for different screen sizes. With a tablet breakpoint, you can change how your site looks on tablets to deliver the best experience for visitors.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"429\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/tablet-preview.png\" alt=\"Live preview on tablet devices in SeedProd\" class=\"wp-image-32135\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/tablet-preview.png 662w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-preview-400x259.png 400w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-preview-50x32.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>We understand how crucial this is for not only designing but also previewing your designs on tablet screens, and with this new feature, you can see how they look on tablets as well as smartphones and desktop devices.</p>\n\n\n\n<p>We’ve pushed this a notch further inside our blocks. Now, you’ll see an additional option to customize the alignment, typography, and spacing just for tablet devices.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"371\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/block-tablet-breakpoints.png\" alt=\"Block customization options for tablet devices in SeedProd\" class=\"wp-image-32136\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/block-tablet-breakpoints.png 662w, https://www.seedprod.com/wp-content/uploads/2024/01/block-tablet-breakpoints-400x224.png 400w, https://www.seedprod.com/wp-content/uploads/2024/01/block-tablet-breakpoints-50x28.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>This means you can alter your designs to display differently on tablets compared to desktops and mobile devices. It’s like having 3 different versions of your site, each tailored to specific screen sizes.</p>\n\n\n\n<p>For example, you could have large headings across 4 lines on desktops but have visitors on tablets see much smaller headings on just 2 lines. This allows you to maximize space on the screen while ensuring visitors won’t need to scroll as much.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"396\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/tablet-customization-example.png\" alt=\"Example of heading customization options on Desktop and tablet devices\" class=\"wp-image-32137\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/tablet-customization-example.png 662w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-customization-example-400x239.png 400w, https://www.seedprod.com/wp-content/uploads/2024/01/tablet-customization-example-50x30.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Additionally, you can <a href=\"https://www.seedprod.com/how-to-hide-image-in-mobile-view/\" title=\"How to Hide Images in Mobile View on WordPress\">hide specific blocks</a> from showing on tablets. So, if a section, row, or block is too distracting for tablet viewers, you can hide it for that device.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"334\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/hide-on-tablet.png\" alt=\"Example of hiding a section in SeedProd from showing on tablet devices\" class=\"wp-image-32138\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/hide-on-tablet.png 662w, https://www.seedprod.com/wp-content/uploads/2024/01/hide-on-tablet-400x202.png 400w, https://www.seedprod.com/wp-content/uploads/2024/01/hide-on-tablet-50x25.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Need some ideas on how to use tablet breakpoints on your website? We’ve got you covered:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>News and Blogging Sites:&nbsp;</strong>Adjust article layouts, font sizes, and image placements to make reading articles on tablets more comfortable and engaging.</li>\n\n\n\n<li><strong>Restaurant Websites:&nbsp;</strong>Modify menu displays and online reservation systems for tablets, providing an optimal browsing experience for customers.</li>\n\n\n\n<li><strong>Real Estate Listings:</strong>&nbsp;Customize property photos, virtual tours, and listing details to display effectively on tablets.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Upgrade Video Popups with Teaser Previews</h2>\n\n\n\n<p>Another exciting feature we’ve released is an addition to the <a href=\"https://www.seedprod.com/announcement-video-popups/\" title=\"Introducing Video Popups: Unlock Next-Level User Engagement\">Video Popup</a> block: <strong>Teaser Videos</strong>.</p>\n\n\n\n<p>Now, you can grab attention immediately by enabling the Teaser Video toggle in your block settings. Your chosen video will naturally play in the background, audio-free, creating an engaging way to draw in your audience.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"318\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/enable-teaser-video.jpg\" alt=\"Enable teaser video in SeedProd video popup block\" class=\"wp-image-32139\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/enable-teaser-video.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/01/enable-teaser-video-400x192.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/01/enable-teaser-video-50x24.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>But it doesn&#8217;t stop there; on clicking the play button, your video restarts with audio and video controls, allowing viewers to watch the entire video at their own pace.&nbsp;</p>\n\n\n\n<p>Alongside this is the ability to show a banner with a custom icon and text.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"359\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/teaser-video-banner-customizations.jpg\" alt=\"Teaser video banner customization options\" class=\"wp-image-32140\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/teaser-video-banner-customizations.jpg 662w, https://www.seedprod.com/wp-content/uploads/2024/01/teaser-video-banner-customizations-400x217.jpg 400w, https://www.seedprod.com/wp-content/uploads/2024/01/teaser-video-banner-customizations-50x27.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>It’s an ideal way to invite users to click and watch your video in full.</p>\n\n\n\n<p>We can think of so many ways to use this feature, it wouldn’t be fair to keep them to ourselves. So, here are some suggestions for using teaser videos to engage your audience:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Product Launches and Demonstrations:</strong>&nbsp;Create anticipation for new products with silent teasers, then reveal in-depth demonstrations or features when users click.</li>\n\n\n\n<li><strong>Event Promotions:</strong>&nbsp;Generate excitement for upcoming events with teaser clips. This approach is perfect for webinars, workshops, or conferences, offering glimpses that encourage users to discover more.</li>\n\n\n\n<li><strong>Special Offers:</strong>&nbsp;Highlight promotions or special offers through teasers, enticing viewers to click through for the full details of the deal.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Your Language: Covered</h2>\n\n\n\n<p>In our ongoing effort to make <a href=\"https://www.seedprod.com\" title=\"SeedProd - Best Drag &amp; Drop WordPress Website Builder\">SeedProd</a> as accessible and user-friendly as possible, we’re thrilled to announce that the plugin is now available in 10 languages.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"450\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/seedprod-translated-to-10-languages.png\" alt=\"SeedProd is translated into 10 languages\" class=\"wp-image-32141\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/seedprod-translated-to-10-languages.png 662w, https://www.seedprod.com/wp-content/uploads/2024/01/seedprod-translated-to-10-languages-400x272.png 400w, https://www.seedprod.com/wp-content/uploads/2024/01/seedprod-translated-to-10-languages-50x34.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>We believe that language should never be a barrier to <a href=\"https://www.seedprod.com/how-to-create-a-wordpress-website-for-beginners/\" title=\"How to Create a WordPress Website for Beginners\">creating stunning websites</a> and that you should feel seen and understood in your native tongue. Therefore, you can now use SeedProd in:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Spanish</li>\n\n\n\n<li>Nederlands</li>\n\n\n\n<li>French</li>\n\n\n\n<li>German</li>\n\n\n\n<li>Italian</li>\n\n\n\n<li>Japanese</li>\n\n\n\n<li>Polish</li>\n\n\n\n<li>Portuguese (Brazil)</li>\n\n\n\n<li>Russian</li>\n\n\n\n<li>Turkish</li>\n</ul>\n\n\n\n<p>With even more translations in the works.&nbsp;</p>\n\n\n\n<h2 class=\"wp-block-heading\">17 New Site Kits</h2>\n\n\n\n<p>Along with these features, we’ve also been working on growing our <a href=\"https://www.seedprod.com/templates/\" title=\"Landing Page Templates\">templates library</a>. With 17 new additions, our total number of themes and landing pages is well over 300.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"281\" src=\"https://www.seedprod.com/wp-content/uploads/2024/01/New-Webite-Kits-jan-24.png\" alt=\"New SeedProd website template kits\" class=\"wp-image-32142\" srcset=\"https://www.seedprod.com/wp-content/uploads/2024/01/New-Webite-Kits-jan-24.png 662w, https://www.seedprod.com/wp-content/uploads/2024/01/New-Webite-Kits-jan-24-400x170.png 400w, https://www.seedprod.com/wp-content/uploads/2024/01/New-Webite-Kits-jan-24-50x21.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Here’s a quick look at the latest theme releases spanning niches like education, travel, food, and technology:</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>Child Day Care Education</li>\n\n\n\n<li>GreenEarth Environmental Theme</li>\n\n\n\n<li>Curbside Food Truck (WooCommerce)</li>\n\n\n\n<li>BondBloom Relationship Coach</li>\n\n\n\n<li>Artisan Construction</li>\n\n\n\n<li>Innovio Tech Blogger (WooCommerce)</li>\n\n\n\n<li>Paint Works Painting Website</li>\n\n\n\n<li>Prose Online Author (WooCommerce)</li>\n\n\n\n<li>LearnWell Tutoring Website</li>\n\n\n\n<li>Technician Service</li>\n\n\n\n<li>Garden Home Improvement</li>\n\n\n\n<li>Expeditions Hiking</li>\n\n\n\n<li>Explore Era Travel Agency (WooCommerce)</li>\n\n\n\n<li>Opulent Salon</li>\n\n\n\n<li>Beatbash Music</li>\n\n\n\n<li>UnityTree Yoga &amp; Fitness</li>\n\n\n\n<li>MotiveWave Motivation Website</li>\n</ol>\n\n\n\n<p>If you don’t see a theme in our library that fits your niche, please&nbsp;<a href=\"https://www.seedprod.com/contact/\" title=\"Contact SeedProd\">contact us with your suggestions</a>. We’re always looking for fresh ways to meet your needs.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Update Your SeedProd Plugin Today</h2>\n\n\n\n<p>We&#8217;re truly excited about these new updates to SeedProd and are positive you&#8217;ll find them equally as thrilling.</p>\n\n\n\n<p>The Teaser Video feature is available now to anyone with a premium SeedProd license. Simply update your plugin and dive in. Tablet Breakpoints and translations are available to everyone, including SeedProd free users.&nbsp;</p>\n\n\n\n<p>However, if you’re new to SeedProd, now is the best time to upgrade to SeedProd Pro and explore everything it offers.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>\n\n\n\n<p>If you have questions about these features, don&#8217;t hesitate to get in touch with our support team or leave a comment on this post. We&#8217;re always ready to help you get the most out of SeedProd, so please keep the suggestions and feedback coming.</p>\n\n\n\n<p>Our commitment to making SeedProd the&nbsp;<a href=\"https://www.seedprod.com/\" title=\"SeedProd\">best WordPress website builder</a>&nbsp;is only getting stronger as we continue to win with our customers.</p>The post <a href=\"https://www.seedprod.com/announcement-tablet-breakpoint-teaser-video/\">Introducing Tablet Breakpoints, Videos Teasers + More</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:69:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"Introducing Video Popups: Unlock Next-Level User Engagement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"https://www.seedprod.com/announcement-video-popups/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 31 Oct 2023 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:11:\"video block\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:11:\"video popup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=31010\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:366:\"<p>Introducing SeedProd\'s new Video Popup Block, designed to skyrocket user engagement. Plus, 12 new website templates for various industries to grow your site.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-video-popups/\">Introducing Video Popups: Unlock Next-Level User Engagement</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Stacey Corrin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:18837:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"722\" height=\"342\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-pop-ups.png\" class=\"attachment-large size-large wp-post-image\" alt=\"SeedProd announcement video popup block\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-pop-ups.png 722w, https://www.seedprod.com/wp-content/uploads/2023/10/video-pop-ups-400x189.png 400w, https://www.seedprod.com/wp-content/uploads/2023/10/video-pop-ups-50x24.png 50w\" sizes=\"auto, (max-width: 722px) 100vw, 722px\" /></div>|||\n<p>We&#8217;re thrilled to roll out another game-changing update for&nbsp;<a href=\"https://www.seedprod.com\" target=\"_blank\" title=\"SeedProd - Best Drag &amp; Drop WordPress Website Builder\" rel=\"noopener\">SeedProd</a>&nbsp;premium users. Introducing the Video Popup Block—a feature designed to boost your website&#8217;s engagement and user experience.</p>\n\n\n\n<p>But that&#8217;s not all; we&#8217;re also unveiling 12 brand-new website template kits to make your site-building journey even smoother. Read on to discover how these updates can transform how you interact with your audience.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-responsive  embed-responsive-16by9\"><iframe loading=\"lazy\" class=\"embed-responsive-item\"   title=\"NEW UPDATE! Introducing Video Popups: Unlock Next-Level User Engagement\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/HNvjx73eNak?feature=oembed&enablejsapi=1\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe></div>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Why Video Popups? The Power of Visual Content</h2>\n\n\n\n<p>In an era where digital engagement is key, video content has become more than just a flashy add-on—it&#8217;s a cornerstone for effective online interaction.</p>\n\n\n\n<p>But don&#8217;t just take our word for it; the numbers speak for themselves. A recent study shows that as many as&nbsp;<a href=\"https://www.oberlo.com/blog/video-marketing-statistics\" target=\"_blank\" rel=\"noopener nofollow\" title=\"\">91% of consumers want to see more online video content</a>&nbsp;from brands. Additionally, 86% of marketing professionals use video as a marketing tool.</p>\n\n\n\n<p>So, what makes video popups so compelling? They blend the immersive power of video with the immediacy of a popup, offering an engaging experience right on your webpage. This combination not only captures attention but also drives action—be it signing up for a newsletter, exploring a product, or simply spending more time on your site.</p>\n\n\n\n<p>With SeedProd&#8217;s new Video Popup Block, you can seamlessly integrate this type of visual content right into your WordPress site.&nbsp;</p>\n\n\n\n<h2 class=\"wp-block-heading\">Getting Started with Video Popups</h2>\n\n\n\n<p>Setting up your new Video Popup Block is a breeze. You don&#8217;t need to be a tech wizard to get things rolling; just follow these simple steps:</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"517\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-popup-block-seedprod.jpg\" alt=\"SeedProd video popup block\" class=\"wp-image-31012\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-popup-block-seedprod.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/10/video-popup-block-seedprod-400x312.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/10/video-popup-block-seedprod-50x39.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Edit Your Page:</strong>&nbsp;Open the page you want to edit with SeedProd.</li>\n\n\n\n<li><strong>Drag and Drop:</strong>&nbsp;Find the Video Popup Block in the blocks sidebar, then drag and drop it onto your page.</li>\n</ul>\n\n\n\n<p>That’s it! From here, you can dive into the customization options to make the video popup truly your own.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Display Videos from Multiple Sources</h3>\n\n\n\n<p>One of the standout features of the Video Popup Block is its versatility in video sourcing. You&#8217;re not limited to just one platform; instead, you have multiple options to choose from:</p>\n\n\n\n<p><strong>YouTube:</strong>&nbsp;Perfect for those who already have a <a href=\"https://www.seedprod.com/youtube-channel-landing-page/\" title=\"How to Make a Super Effective YouTube Channel Landing Page\">YouTube channel</a> or want to feature trending videos. Just paste the video URL, and you&#8217;re good to go.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"415\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-source-youtube.png\" alt=\"YouTube video popup source SeedProd\" class=\"wp-image-31013\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-source-youtube.png 662w, https://www.seedprod.com/wp-content/uploads/2023/10/video-source-youtube-400x251.png 400w, https://www.seedprod.com/wp-content/uploads/2023/10/video-source-youtube-50x31.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p><strong>Vimeo:</strong>&nbsp;If you prefer the more professional and ad-free environment of Vimeo, this option is for you. Again, all you need is the video URL.</p>\n\n\n\n<p><strong>Custom:</strong>&nbsp;Want full control over your video content? You can upload your custom videos directly via the WordPress Media Library or from an alternative URL. This is ideal for exclusive content that you don&#8217;t want to share on public platforms.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"469\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-source-custom.png\" alt=\"Video popup form a custom source in WordPress\" class=\"wp-image-31014\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-source-custom.png 662w, https://www.seedprod.com/wp-content/uploads/2023/10/video-source-custom-400x283.png 400w, https://www.seedprod.com/wp-content/uploads/2023/10/video-source-custom-50x35.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Improve User Experience with Versatile Video Options</h3>\n\n\n\n<p>The Video Popup Block isn&#8217;t just about embedding a video; it&#8217;s about providing an optimized viewing experience for your visitors. Let&#8217;s break down the customization options you have at your disposal:</p>\n\n\n\n<p><strong>Autoplay:</strong>&nbsp;Ideal for grabbing immediate attention, autoplay starts the video as soon as the page loads. There’s even a separate toggle to autoplay videos on mobile devices. Use it for welcome videos or important announcements.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"295\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/autoplay-video-on-mobile.png\" alt=\"Autoplay video popup on mobile in WordPress\" class=\"wp-image-31015\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/autoplay-video-on-mobile.png 662w, https://www.seedprod.com/wp-content/uploads/2023/10/autoplay-video-on-mobile-400x178.png 400w, https://www.seedprod.com/wp-content/uploads/2023/10/autoplay-video-on-mobile-50x22.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p><strong>Mute:</strong>&nbsp;Sometimes, you want the video to be seen, not heard—especially if it&#8217;s supplementary to the main content. The mute option ensures your video doesn&#8217;t disrupt the user experience.</p>\n\n\n\n<p><strong>Loop:</strong>&nbsp;Have a short video clip that you want to play continuously? The loop feature keeps the video playing in a never-ending cycle, perfect for background visuals or ambiance.</p>\n\n\n\n<p><strong>Show Player Controls:</strong>&nbsp;Give your users the freedom to pause, play, or skip through the video with visible player controls. This is great for longer, informative videos where viewers may want to revisit certain sections.</p>\n\n\n\n<p><strong>Privacy Mode:</strong>&nbsp;For those concerned about data privacy, this option ensures that no cookies are stored on the viewer&#8217;s computer until they play the video.</p>\n\n\n\n<p><strong>Lazy Load:</strong>&nbsp;Speed up your page loading time by only loading the video when it&#8217;s visible to the user. This is crucial for mobile users or those with slower internet connections.</p>\n\n\n\n<p><strong>Suggested Videos:</strong>&nbsp;At the end of the video, you can display suggested videos to keep the viewer engaged. Choose between videos from the current channel or suggest any video.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"290\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/suggested-videos.png\" alt=\"Suggested video settings in SeedProd video popup block\" class=\"wp-image-31016\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/suggested-videos.png 662w, https://www.seedprod.com/wp-content/uploads/2023/10/suggested-videos-400x175.png 400w, https://www.seedprod.com/wp-content/uploads/2023/10/suggested-videos-50x22.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Use this to guide users to more of your own content or relevant third-party videos.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Keep Viewers Engaged with Sticky Video</h3>\n\n\n\n<p>The Sticky Video feature takes user engagement to the next level. Imagine your viewers can scroll through your website without missing a second of your video content. That&#8217;s exactly what Sticky Video accomplishes.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"356\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/sticky-video-popup.gif\" alt=\"Sticky video popup example in WordPress\" class=\"wp-image-31017\"/></figure>\n\n\n\n<p>When this feature is enabled, the video minimizes to the bottom corner of the page as the user scrolls. This way, your audience can multitask—exploring other parts of your page while staying tuned into your video.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Increase Click-Throughs with Image Overlay</h3>\n\n\n\n<p>While the video content is the star of the show, the first thing your audience sees is the thumbnail image. That&#8217;s why we&#8217;ve included customization options that not only make your video popups more visually appealing but also encourage clicks.</p>\n\n\n\n<p>By enabling the custom thumbnail option, you can use your own image to give viewers a sneak peek of the video content. A compelling thumbnail can significantly increase your click-through rates.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"408\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-thumbnail.jpg\" alt=\"Custom video thumbnail settings in WordPress\" class=\"wp-image-31018\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-thumbnail.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-thumbnail-400x247.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-thumbnail-50x31.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>To go with your custom thumbnail, you can add a custom play icon to make it clear that the image is clickable and leads to a video.</p>\n\n\n\n<p>Want to match your website’s branding? Choose from multiple icons and change their color to anything you like with a few clicks.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"407\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-icon.jpg\" alt=\"Custom video play icon settings\" class=\"wp-image-31019\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-icon.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-icon-400x246.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/10/custom-video-icon-50x31.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>When enabled, the video can even open in a lightbox, providing a focused and immersive viewing experience. This is especially useful for videos you want to highlight or that contain important information.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"507\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-lightbox-popup.jpg\" alt=\"Video lightbox popup example\" class=\"wp-image-31020\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/video-lightbox-popup.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/10/video-lightbox-popup-400x306.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/10/video-lightbox-popup-50x38.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>In summary, this new feature is more than just a way to display videos on your site.</p>\n\n\n\n<p>Whether you’re a content creator, agency, <a href=\"https://www.seedprod.com/how-to-set-up-an-online-store-wordpress/\" title=\"How to Set Up an Online Store in WordPress (Ultimate Guide)\">online store</a>, or small business, it&#8217;s an all-in-one solution for engaging and educating your audience in WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">More SeedProd News</h2>\n\n\n\n<p>As if the Video Popup Block wasn&#8217;t enough to excite you, we&#8217;ve got another big update—12 brand-new <a href=\"https://www.seedprod.com/templates/\" title=\"\">website template kits</a> designed to cater to various niches.</p>\n\n\n\n<p>Whether you&#8217;re in the hospitality sector, healthcare, or eCommerce, there&#8217;s something for everyone.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"534\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/october-themes.jpg\" alt=\"SeedProd new WordPress themes for October\" class=\"wp-image-31021\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/october-themes.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/10/october-themes-400x323.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/10/october-themes-50x40.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Here&#8217;s a quick rundown:</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li><strong>Fundraising Charity:</strong>&nbsp;Perfect for non-profits looking to make a difference.</li>\n\n\n\n<li><strong>Property Agency:</strong>&nbsp;Ideal for <a href=\"https://www.seedprod.com/how-to-create-a-real-estate-website/\" title=\"How to Create a Real Estate Website in WordPress\">real estate</a> agencies aiming to showcase properties in a sleek, professional manner.</li>\n\n\n\n<li><strong>Costai Hotel:&nbsp;</strong>Designed for hotels and resorts, offering a luxurious user experience.</li>\n\n\n\n<li><strong>Empethic Clinic:</strong>&nbsp;Tailored for healthcare providers, focusing on accessibility and information.</li>\n\n\n\n<li><strong>Modern Beauty (WooCommerce):</strong>&nbsp;A stylish and functional kit for beauty eCommerce sites.</li>\n\n\n\n<li><strong>Magnolia Real Estate:</strong>&nbsp;Another great option for property listings focusing on visuals and details.</li>\n\n\n\n<li><strong>Nail and Beauty Salon:</strong>&nbsp;For salons looking to attract new clients and showcase their services.</li>\n\n\n\n<li><strong>Design Studio:</strong>&nbsp;Ideal for creative agencies and freelancers.</li>\n\n\n\n<li><strong>Fork Flask Restaurant:&nbsp;</strong>Perfect for eateries looking to display menus and take reservations online.</li>\n\n\n\n<li><strong>Grape &amp; Vines Winery (WooCommerce)</strong>: Tailored for wineries and liquor stores, complete with eCommerce support.</li>\n\n\n\n<li><strong>Fashion and Model Website:</strong>&nbsp;A chic template for fashion blogs, portfolios, and eCommerce.</li>\n\n\n\n<li><strong>Elite Consulting v2:</strong>&nbsp;A versatile template for consulting firms offering a professional, customizable layout.</li>\n</ol>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"521\" src=\"https://www.seedprod.com/wp-content/uploads/2023/10/october-themes-2.jpg\" alt=\"SeedProd new WordPress themes for October 2\" class=\"wp-image-31022\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/10/october-themes-2.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/10/october-themes-2-400x315.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/10/october-themes-2-50x39.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Each&nbsp;template kit&nbsp;is fully customizable and designed to work seamlessly with all SeedProd features, including the new Video Popup Block.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Ready to Engage Visitors with Video Popups?</h2>\n\n\n\n<p>There&#8217;s never been a better time to improve your website with SeedProd. With the new Video Popup Block and 12 website kits, you have everything you need to create an engaging and effective website. Whether you aim to boost interaction with compelling video content or give your site a fresh, professional look, we&#8217;ve got you covered.</p>\n\n\n\n<p>Anyone with a paid <a href=\"https://www.seedprod.com/pricing/\" title=\"\">SeedProd license</a> can update the plugin today to access all these new features and templates. If you have any questions or need help getting started,&nbsp;<a href=\"https://www.seedprod.com/contact/\" title=\"Contact SeedProd\">our support team</a>&nbsp;is always here to assist you.</p>\n\n\n\n<p>Are you still using the free version of SeedProd? Well, now’s your chance to upgrade. Until Friday, November 3rd, 2023, at midnight EST,&nbsp; we’re offering a huge <strong>Halloween discount with 60% off for lite users only!</strong></p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>\n\n\n\n<p>As always, thank you for supporting us in our mission to make SeedProd the&nbsp;<a href=\"https://www.seedprod.com/\" title=\"SeedProd Best WordPress Website Builder\">best WordPress website builder</a>.</p>The post <a href=\"https://www.seedprod.com/announcement-video-popups/\">Introducing Video Popups: Unlock Next-Level User Engagement</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:72:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:3:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"Introducing New Author Pages, Post Layouts &amp; More\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"https://www.seedprod.com/announcement-custom-author-pages/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 29 Aug 2023 12:00:37 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:6:{i:0;a:5:{s:4:\"data\";s:13:\"Announcements\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:4:\"Blog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:18:\"custom author page\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:11:\"post layout\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:12:\"website kits\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://www.seedprod.com/?p=29479\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:365:\"<p>Today, we’re thrilled to announce new updates to SeedProd: Custom Author Pages and Post Block Layouts. These new additions make customizing WordPress easier.</p>\nThe post <a href=\"https://www.seedprod.com/announcement-custom-author-pages/\">Introducing New Author Pages, Post Layouts & More</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Stacey Corrin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:23993:\"<div><img loading=\"lazy\" decoding=\"async\" width=\"722\" height=\"342\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/introducing-new-author-pages-2nd.png\" class=\"attachment-large size-large wp-post-image\" alt=\"announcement author page templates and posts layouts\" style=\"margin-bottom: 10px;\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/introducing-new-author-pages-2nd.png 722w, https://www.seedprod.com/wp-content/uploads/2023/08/introducing-new-author-pages-2nd-400x189.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/introducing-new-author-pages-2nd-50x24.png 50w\" sizes=\"auto, (max-width: 722px) 100vw, 722px\" /></div>|||\n<p>Today, we’re thrilled to announce an exciting new update to <a href=\"https://www.seedprod.com\" title=\"SeedProd - Best Drag &amp; Drop WordPress Website Builder\">SeedProd</a>: Custom Author Pages and Post Block Layouts.</p>\n\n\n\n<p>These new additions make customizing your WordPress site easier while allowing you to add crucial SEO signals to boost your search engine rankings.</p>\n\n\n\n<p>We truly believe that you’ll love these updates, so without further ado, let’s find out how they work.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-responsive  embed-responsive-16by9\"><iframe loading=\"lazy\" class=\"embed-responsive-item\"   title=\"NEW Author Pages, Post Block Layouts and More | SeedProd Update\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/YI16mWO_WoI?feature=oembed&enablejsapi=1\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe></div>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Boost SEO with Custom Author Pages</h2>\n\n\n\n<p>Search engine optimization (SEO) is essential for ensuring your website ranks in search results. Google uses the E.E.A.T framework, which stands for Experience, Expertise, Authoritativeness, and Trustworthiness, to determine ​​which websites should rank higher.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"400\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/Goolge-EEAT-explained-1.png\" alt=\"Google E.E.A.T framework explained\" class=\"wp-image-29502\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/Goolge-EEAT-explained-1.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/Goolge-EEAT-explained-1-400x242.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/Goolge-EEAT-explained-1-50x30.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Author pages can support this ranking factor by:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Listing qualifications, experience, and publications to show an author’s expertise</li>\n\n\n\n<li>Linking to other content, social media profiles, and awards to demonstrate an author’s authoritativeness</li>\n\n\n\n<li>Including an informative and well-written bio highlighting any conflicts of interest to show an author’s trustworthiness</li>\n</ul>\n\n\n\n<p>What’s more, author pages can also indirectly support E.E.A.T by improving the overall quality of your website.</p>\n\n\n\n<p>When users see that your site has author pages, they’re likely to trust its content. This can lead to more time spent on your site, more clicks, and more social shares, all of which Google takes into account when ranking websites.</p>\n\n\n\n<p>At SeedProd, we believe that SEO should be easy, no matter your level of experience. That’s why author pages are top of our list of new plugin features.</p>\n\n\n\n<p>Previously, when using SeedProd, a typical author page would display an archive of the author’s posts.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"403\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-post-archive.png\" alt=\"SeedProd author post archive page\" class=\"wp-image-29481\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-post-archive.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/author-post-archive-400x244.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/author-post-archive-50x30.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>With this update, you can <a href=\"https://www.seedprod.com/custom-wordpress-author-page/\" title=\"\">create an Author Page</a> template that allows you to customize the page with any of SeedProds’ <a href=\"https://www.seedprod.com/wordpress-blocks/\" title=\"WordPress Blocks\">WordPress blocks</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"438\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/SeedProd-author-page-template.png\" alt=\"SeedProd Author Page Template\" class=\"wp-image-29482\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/SeedProd-author-page-template.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/SeedProd-author-page-template-400x265.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/SeedProd-author-page-template-50x33.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Simple Global Author Pages</h3>\n\n\n\n<p>After creating an author page template, you can use the new Author Bio block to display information about a specific author.&nbsp;</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"427\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block.png\" alt=\"SeedProd Author Bio block\" class=\"wp-image-29483\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block-400x258.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block-50x32.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>The block pulls this information from the WordPress user profile, so any HTML, such as links to social media, are displayed automatically.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"435\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block-settings.png\" alt=\"Author Bio block settings\" class=\"wp-image-29484\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block-settings.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block-settings-400x263.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/author-bio-block-settings-50x33.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>You can also add the Posts block to this page and select the default query to show that author’s blog posts.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"445\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-posts.png\" alt=\"Author posts block\" class=\"wp-image-29485\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-posts.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/author-posts-400x269.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/author-posts-50x34.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>This approach is a great way to quickly establish an author’s presence on your WordPress website. However, to add customizations specific to each author, you’ll need to make a custom author page using their user ID.</p>\n\n\n\n<p>Let’s look at how to do that with SeedProd next.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Custom Pages for Each Author</h3>\n\n\n\n<p><a href=\"https://www.seedprod.com/create-a-custom-page-in-wordpress/\" title=\"How to Create a Custom Page in WordPress (Step-by-Step)\">Creating a custom page</a> for each site author is an excellent way to meet the E.E.A.T guidelines we mentioned earlier. Instead of simply showing the same generic page for all writers, you can tailor each page to include content relevant to specific authors.</p>\n\n\n\n<p>To do this, create a new author page template as before, but this time, you’ll need to enter the user ID of the author you’re making a custom page for.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"453\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-page-user-id.png\" alt=\"Author Page template with User ID\" class=\"wp-image-29486\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-page-user-id.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/author-page-user-id-400x274.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/author-page-user-id-50x34.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>If you need help, you can see this guide on&nbsp;<a target=\"_blank\" href=\"https://www.wpbeginner.com/beginners-guide/how-to-find-post-category-tag-comments-or-user-id-in-wordpress/#find-user-id\" rel=\"noreferrer noopener\">how to find the user ID in WordPress</a>.</p>\n\n\n\n<p>Now you can go ahead and customize the page to include that’s author’s content. For example, with the Posts block, you can display that author’s blog posts to demonstrate their expertise and authority.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"379\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/recent-posts-by-author.png\" alt=\"Show recent posts by author\" class=\"wp-image-29487\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/recent-posts-by-author.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/recent-posts-by-author-400x229.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/recent-posts-by-author-50x29.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>You can also display an author’s social media profile icons so users can follow their updates on other platforms.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"325\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-page-social-icons.png\" alt=\"Author page social media icons\" class=\"wp-image-29488\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/author-page-social-icons.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/author-page-social-icons-400x196.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/author-page-social-icons-50x25.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Embedding a feed of their most <a href=\"https://www.seedprod.com/twitter-widget-wordpress/\" title=\"How to Add a Twitter Widget to WordPress (Step-by-Step)\">recent Tweets</a> is another excellent way to personalize an author’s page while automatically updating it with fresh content.</p>\n\n\n\n<p>Need even more customization ideas? Check these out:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://www.seedprod.com/how-to-create-a-contact-form-in-wordpress/\" title=\"How to Add a Contact Form in WordPress (Beginners Guide)\">Add a contact form</a> for users to contact specific authors directly</li>\n\n\n\n<li>Display a welcome video with a personal message from the author</li>\n\n\n\n<li>Add frequently asked questions to highlight important author details</li>\n\n\n\n<li>Display a behind-the-scenes gallery featuring candid shots of the author</li>\n\n\n\n<li>Add a payment button so users can tip the author to show their appreciation</li>\n</ul>\n\n\n\n<p>The options are limitless, and by the end, you’ll have beautiful, SEO-friendly pages for every author on your website.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"389\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/SEO-friendly-custom-author-page.png\" alt=\"SEO-friendly custom WordPress author page example\" class=\"wp-image-29489\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/SEO-friendly-custom-author-page.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/SEO-friendly-custom-author-page-400x235.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/SEO-friendly-custom-author-page-50x29.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">More Customization Options for Blog Posts</h2>\n\n\n\n<p>Another update we’re excited to release is the ability to customize the Posts block layout further. Now you can customize <a href=\"https://www.seedprod.com/how-to-create-a-blog-page-on-wordpress/\" title=\"How to Create a Blog Page on WordPress (2 Easy Ways)\">blog pages</a> to meet different styles and aesthetics with a few clicks.</p>\n\n\n\n<p>Previously you could display blog posts in a simple linear layout. However, we knew that further down the line, you’d need more ways to make your blog stand out.</p>\n\n\n\n<p>With this in mind, we’ve added Skins and Layouts to the Posts block, allowing you to quickly switch up your blog design without coding.</p>\n\n\n\n<h3 class=\"wp-block-heading\">1-Click Skin Styles</h3>\n\n\n\n<p>Let’s look at Skins first, which are like mini themes for your blog page. In total, there are four skins, and you can select one by choosing it from the Skins dropdown.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"277\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-skin-styles.png\" alt=\"Posts block Skin styles\" class=\"wp-image-29490\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-skin-styles.png 662w, https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-skin-styles-400x167.png 400w, https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-skin-styles-50x21.png 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>The Classic skin has the typical blog list layout you’re used to.</p>\n\n\n\n<p>However, the Card skin has a more modern design, featuring a prominent author profile picture. This skin also displays the post category in the top-right corner of the featured image.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"388\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/card-skin-styles.jpg\" alt=\"Card Skin styles\" class=\"wp-image-29491\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/card-skin-styles.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/card-skin-styles-400x234.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/card-skin-styles-50x29.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>The Creative Skin is another modern take on a blog list. It features an overlapping info box and a prominent category bubble above the post title and description.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"467\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/creative-skin-style.jpg\" alt=\"Creative Skin style\" class=\"wp-image-29492\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/creative-skin-style.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/creative-skin-style-400x282.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/creative-skin-style-50x35.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Last is the Minimal skin which strips things back to a cleaner style that’s easy on the eyes. It features plenty of white space and a smaller image focusing more on the post content.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"316\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/minimal-skin-style.jpg\" alt=\"Minimal skin style\" class=\"wp-image-29493\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/minimal-skin-style.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/minimal-skin-style-400x191.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/minimal-skin-style-50x24.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Creative Layouts</h3>\n\n\n\n<p>Besides new skins, we’ve also added layouts to the Posts block settings. First is the Grid layout, which aligns all posts uniformly on the page.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"284\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-layouts.jpg\" alt=\"Posts block Layouts\" class=\"wp-image-29494\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-layouts.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-layouts-400x172.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/posts-block-layouts-50x21.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Then there’s the Masonry layout which doesn’t have a fixed row height. With this option, you can display a more Pinterest-like grid of posts, which helps you maximize page space and use images of different shapes and proportions.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"535\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/Masonry-layout.jpg\" alt=\"Masonry posts layout\" class=\"wp-image-29495\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/Masonry-layout.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/Masonry-layout-400x323.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/Masonry-layout-50x40.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Last is the Carousel layout, which allows you to display blog posts in an automatically sliding carousel.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"526\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/carousel-layout.jpg\" alt=\"Carousel posts layout\" class=\"wp-image-29496\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/carousel-layout.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/carousel-layout-400x318.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/carousel-layout-50x40.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>You can combine these layouts in any way that you like.</p>\n\n\n\n<p>For example, you could show a scrolling carousel of recent posts at the top of your blog page. Then list a Masonry grid of posts from specific categories below it.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"536\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/carousel-and-grid-posts.jpg\" alt=\"Carousel and Grid posts layouts\" class=\"wp-image-29497\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/carousel-and-grid-posts.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/carousel-and-grid-posts-400x324.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/carousel-and-grid-posts-50x40.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>Alternatively, you could create a magazine-style layout with different sections for each category and a more general blog layout beneath.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"542\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/magazine-style-layout.jpg\" alt=\"Magazine style posts layout\" class=\"wp-image-29498\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/magazine-style-layout.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/magazine-style-layout-400x327.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/magazine-style-layout-50x41.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>If that wasn’t enough, the Posts block has several new Advanced customization options. You can customize the content area background, border, and taxonomy badge to match your website’s design.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"448\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/advanced-posts-block-settings.jpg\" alt=\"Advanced posts block customization settings for content area\" class=\"wp-image-29499\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/advanced-posts-block-settings.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/advanced-posts-block-settings-400x271.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/advanced-posts-block-settings-50x34.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">10 New Website Theme Kits</h2>\n\n\n\n<p>Along with the updates above, we’ve released 10 stunning new <a href=\"https://www.seedprod.com/templates/\" title=\"Landing Page Templates\">site kits</a> that you can try out right away.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"662\" height=\"499\" src=\"https://www.seedprod.com/wp-content/uploads/2023/08/august-website-template-kits.jpg\" alt=\"New SeedProd website template kits\" class=\"wp-image-29500\" srcset=\"https://www.seedprod.com/wp-content/uploads/2023/08/august-website-template-kits.jpg 662w, https://www.seedprod.com/wp-content/uploads/2023/08/august-website-template-kits-400x302.jpg 400w, https://www.seedprod.com/wp-content/uploads/2023/08/august-website-template-kits-50x38.jpg 50w\" sizes=\"auto, (max-width: 662px) 100vw, 662px\" /></figure>\n\n\n\n<p>They include themes for:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Yoga &amp; Wellness</li>\n\n\n\n<li>Tattoo Studio &amp; Barber Shop</li>\n\n\n\n<li>Insurance website</li>\n\n\n\n<li>Energy Saving website</li>\n\n\n\n<li>Charity website</li>\n\n\n\n<li>Newspaper Magazine</li>\n\n\n\n<li>Shipping agency</li>\n</ul>\n\n\n\n<p>Plus, you’ll find 3 new WooCommerce themes for Wedding &amp; Catering, Cleaning Service, and Optician.&nbsp;</p>\n\n\n\n<h2 class=\"wp-block-heading\">Update Your SeedProd Plugin Today</h2>\n\n\n\n<p>As you can see, this update introduces several powerful changes that make WordPress customizations much easier. Whether you’re a beginner getting your first taste of code-free site building, or a developer streamlining your workflow, there’s something for everyone.</p>\n\n\n\n<p>But to enjoy these features, you’ll need a <a href=\"https://www.seedprod.com/pricing/\" title=\"\">premium SeedProd subscription</a>. So if you haven’t already, get SeedProd Pro and take these features for a spin.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-white-color has-text-color has-background has-link-color wp-element-button\" href=\"https://www.seedprod.com/pricing/\" style=\"background-color:#17a349\">Get Started with SeedProd Today</a></div>\n</div>\n\n\n\n<p>We still have more improvements planned for SeedProd, and we&#8217;d love to know what issues or questions you have.</p>\n\n\n\n<p>Our product and dev teams are paying close attention over the coming months, so don&#8217;t be afraid to drop a comment below or&nbsp;<a href=\"https://www.seedprod.com/contact/\" title=\"\">contact our support team</a>&nbsp;with your feedback and feature requests.</p>\n\n\n\n<p>As always, thank you for helping us make SeedProd the&nbsp;<a href=\"https://www.seedprod.com/\" title=\"\">best WordPress website builder</a>.</p>The post <a href=\"https://www.seedprod.com/announcement-custom-author-pages/\">Introducing New Author Pages, Post Layouts & More</a> appeared first on <a href=\"https://www.seedprod.com\">SeedProd</a>.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:53:\"https://www.seedprod.com/category/release-notes/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:22:{s:4:\"date\";s:29:\"Mon, 13 Apr 2026 14:12:08 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:6:\"server\";s:10:\"cloudflare\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:13:\"cf-edge-cache\";s:25:\"cache, platform=wordpress\";s:15:\"referrer-policy\";s:26:\"no-referrer-when-downgrade\";s:13:\"last-modified\";s:29:\"Fri, 10 Apr 2026 13:22:57 GMT\";s:4:\"etag\";s:36:\"W/\"c864a646f12b8c5f9abb0fbf58a548e0\"\";s:18:\"permissions-policy\";s:342:\"private-state-token-redemption=(self \"https://www.google.com\" \"https://www.gstatic.com\" \"https://recaptcha.net\" \"https://challenges.cloudflare.com\" \"https://hcaptcha.com\"), private-state-token-issuance=(self \"https://www.google.com\" \"https://www.gstatic.com\" \"https://recaptcha.net\" \"https://challenges.cloudflare.com\" \"https://hcaptcha.com\")\";s:12:\"x-robots-tag\";s:15:\"noindex, follow\";s:4:\"link\";s:172:\"<https://www.seedprod.com/wp-json/>; rel=\"https://api.w.org/\", <https://www.seedprod.com/wp-json/wp/v2/categories/5>; rel=\"alternate\"; title=\"JSON\"; type=\"application/json\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"x-xss-protection\";s:13:\"1; mode=block\";s:22:\"x-content-type-options\";s:7:\"nosniff\";s:16:\"content-encoding\";s:4:\"gzip\";s:3:\"age\";s:5:\"63891\";s:13:\"cache-control\";s:16:\"max-age=31536000\";s:15:\"cf-cache-status\";s:3:\"HIT\";s:3:\"nel\";s:64:\"{\"report_to\":\"cf-nel\", \"success_fraction\":0.0, \"max_age\":604800}\";s:13:\"server-timing\";s:55:\"cfCacheStatus;desc=\"HIT\", cfEdge;dur=15, cfOrigin;dur=0\";s:9:\"report-to\";s:265:\"{\"group\":\"cf-nel\", \"max_age\":604800, \"endpoints\":[{\"url\":\"https://a.nel.cloud