^/]+/([^/]+)/(feed|rdf|rss|rss2|atom)/?$\";s:49:\"index.php?attachment=$matches[1]&feed=$matches[2]\";s:46:\"(en)/[^/]+/([^/]+)/comment-page-([0-9]{1,})/?$\";s:67:\"index.php?lang=$matches[1]&attachment=$matches[2]&cpage=$matches[3]\";s:41:\"[^/]+/([^/]+)/comment-page-([0-9]{1,})/?$\";s:50:\"index.php?attachment=$matches[1]&cpage=$matches[2]\";s:27:\"(en)/[^/]+/([^/]+)/embed/?$\";s:60:\"index.php?lang=$matches[1]&attachment=$matches[2]&embed=true\";s:22:\"[^/]+/([^/]+)/embed/?$\";s:43:\"index.php?attachment=$matches[1]&embed=true\";}','auto'),(645,'pll_dismissed_notices','a:1:{i:0;s:6:\"wizard\";}','auto'),(646,'edd_sl_a326284078c6367b82a08f340077cf27','a:2:{s:7:\"timeout\";i:1776103878;s:5:\"value\";s:7218:\"{\"new_version\":\"3.8.2\",\"slug\":\"polylang-pro\",\"package\":\"\",\"download_link\":\"\",\"tested\":\"6.9.4\",\"banners\":{\"high\":\"\",\"low\":\"\"},\"case\":5,\"name\":\"Polylang Pro\",\"url\":\"https:\\/\\/polylang.pro\\/pricing\\/polylang-pro\\/?attribute_pa_sites=1-site\",\"homepage\":\"https:\\/\\/polylang.pro\\/pricing\\/polylang-pro\\/?attribute_pa_sites=1-site\",\"stable_version\":\"3.8.2\",\"stable_tag\":\"3.8.2\",\"last_updated\":\"2026-04-07\",\"requires\":\"6.5\",\"requires_php\":\"7.4\",\"author\":\"WP SYNTEX\",\"sections\":{\"changelog\":\"<!-- wp:preformatted -->\\n<pre class=\\\"wp-block-preformatted\\\">= 3.8.2 (2026-04-07) =<br><br>* Pro: Fix refresh issues in block editor languages panel #2965<br>* Pro: Fix error when unlinking 2 translations in block editor #2970<br>* Pro: Fix fatal error when a repeater is previously created in ACF Pro but ACF is active #2972<br>* Fix settings redirect in Playground #1840<br>* Fix possible fatal error when the default language has been corrupted in DB #1843<br><br>= 3.8.1 (2026-03-19) =<br><br>* Fix fatal error when the cache is suspended #1837 #1839<br><br>= 3.8 (2026-03-17) =<br><br>* Requires PHP 7.4 and WP 6.5 as minimum version<br>* Pro: Use autonomous updater #2475<br>* Pro: Add capabilities allowing to control permissions per language<br>* Pro: Add capabilities to control access to languages and strings translations<br>* Pro: Allow to manage languages and settings with WP CLI #2653<br>* Pro: Add smart duplication in site editor #2559<br>* Pro: Add support for DeepL glossaries #2687<br>* Pro: Add locale fallback support to machine translation #2685<br>* Pro: Add Support encoding for block attributes in wpml-config.xml #1683, #2660<br>* Pro: Improve extensibility of the block editor languages panel #2553<br>* Pro: Add support for new blocks introduced in WP 7.0 #2933 #2941<br>* Pro: Hide language selector on inner blocks in Widget Block Editor #2900<br>* Pro: Fix page template not copied when creating a new page translation in the block editor #2581<br>* Pro: Fix SVG icons lost when using machine translation<br>* Pro: Fix a performance issue with the translation of ACF labels #2670<br>* Pro: Fix product status wrongly modified when updating a product with the REST API #2540<br>* Pro: Fix inactive languages not displayed when they should in REST API #2791<br>* Pro: Fix translation of ACF repeaters with pagination #2674<br>* Pro: Fix ACF\'s layout fields instructions #2889<br>* Pro: Fix ACF\'s taxonomy fields not synchronized #2948<br>* Pro: Fix event dates of The Events Calendar not duplicated #2894<br>* Add language switcher block and navigation language switcher block #1811<br>* Add support for multiple encodings in wpml-config.xml #1679, #2655<br>* Enforce transients in DB and in object cache are synchronized #1653, #2598<br>* Enforce passing all translations when saving the translations of a post or term #1690<br>* Hide the admin language filter when editing posts #1698<br>* Improve performance by preventing DB queries to fetch the language terms #1650<br>* Fix edge cases where the translation group could be corrupted #1690<br>* Fix a fatal error on multisite when saving a post after having switched to a site without Polylang #1700<br>* Fix a fatal error when translating a custom table #1730<br>* Fix warning when requesting a non-existing language #1665<br>* Fix strings translations import with WP Importer #1637<br>* Fix edge cases leading to wrong languages order #1777<br>* Fix a fatal error with the plugin Groups #1834<br><br>See [changelog.txt](<a href=\\\"https:\\/\\/plugins.svn.wordpress.org\\/polylang\\/trunk\\/changelog.txt\\\">https:\\/\\/plugins.svn.wordpress.org\\/polylang\\/trunk\\/changelog.txt<\\/a>) for older changelog<\\/pre>\\n<!-- \\/wp:preformatted -->\"},\"icons\":{\"2x\":\"https:\\/\\/polylang.pro\\/content\\/uploads\\/2024\\/01\\/polylang-related-product-blue.svg\",\"1x\":\"https:\\/\\/polylang.pro\\/content\\/uploads\\/2024\\/01\\/polylang-related-product-blue.svg\"},\"pack_data\":[],\"changelog\":[\"<!-- wp:preformatted -->\\n<pre class=\\\"wp-block-preformatted\\\">= 3.8.2 (2026-04-07) =<br><br>* Pro: Fix refresh issues in block editor languages panel #2965<br>* Pro: Fix error when unlinking 2 translations in block editor #2970<br>* Pro: Fix fatal error when a repeater is previously created in ACF Pro but ACF is active #2972<br>* Fix settings redirect in Playground #1840<br>* Fix possible fatal error when the default language has been corrupted in DB #1843<br><br>= 3.8.1 (2026-03-19) =<br><br>* Fix fatal error when the cache is suspended #1837 #1839<br><br>= 3.8 (2026-03-17) =<br><br>* Requires PHP 7.4 and WP 6.5 as minimum version<br>* Pro: Use autonomous updater #2475<br>* Pro: Add capabilities allowing to control permissions per language<br>* Pro: Add capabilities to control access to languages and strings translations<br>* Pro: Allow to manage languages and settings with WP CLI #2653<br>* Pro: Add smart duplication in site editor #2559<br>* Pro: Add support for DeepL glossaries #2687<br>* Pro: Add locale fallback support to machine translation #2685<br>* Pro: Add Support encoding for block attributes in wpml-config.xml #1683, #2660<br>* Pro: Improve extensibility of the block editor languages panel #2553<br>* Pro: Add support for new blocks introduced in WP 7.0 #2933 #2941<br>* Pro: Hide language selector on inner blocks in Widget Block Editor #2900<br>* Pro: Fix page template not copied when creating a new page translation in the block editor #2581<br>* Pro: Fix SVG icons lost when using machine translation<br>* Pro: Fix a performance issue with the translation of ACF labels #2670<br>* Pro: Fix product status wrongly modified when updating a product with the REST API #2540<br>* Pro: Fix inactive languages not displayed when they should in REST API #2791<br>* Pro: Fix translation of ACF repeaters with pagination #2674<br>* Pro: Fix ACF\'s layout fields instructions #2889<br>* Pro: Fix ACF\'s taxonomy fields not synchronized #2948<br>* Pro: Fix event dates of The Events Calendar not duplicated #2894<br>* Add language switcher block and navigation language switcher block #1811<br>* Add support for multiple encodings in wpml-config.xml #1679, #2655<br>* Enforce transients in DB and in object cache are synchronized #1653, #2598<br>* Enforce passing all translations when saving the translations of a post or term #1690<br>* Hide the admin language filter when editing posts #1698<br>* Improve performance by preventing DB queries to fetch the language terms #1650<br>* Fix edge cases where the translation group could be corrupted #1690<br>* Fix a fatal error on multisite when saving a post after having switched to a site without Polylang #1700<br>* Fix a fatal error when translating a custom table #1730<br>* Fix warning when requesting a non-existing language #1665<br>* Fix strings translations import with WP Importer #1637<br>* Fix edge cases leading to wrong languages order #1777<br>* Fix a fatal error with the plugin Groups #1834<br><br>See [changelog.txt](<a href=\\\"https:\\/\\/plugins.svn.wordpress.org\\/polylang\\/trunk\\/changelog.txt\\\">https:\\/\\/plugins.svn.wordpress.org\\/polylang\\/trunk\\/changelog.txt<\\/a>) for older changelog<\\/pre>\\n<!-- \\/wp:preformatted -->\"],\"plugin\":\"polylang-pro\\/polylang.php\",\"id\":\"polylang-pro\\/polylang.php\"}\";}','off'),(647,'category_children','a:0:{}','auto');
